import { Question } from '../types';

export interface ParsedQuestionContent {
    stem: string;
    options: { [key: string]: string | undefined };
}

/**
 * Sanitizes option text to remove Metadata leaks (P1=..., P7=..., GUIA_TRAPSCAN).
 * Returns a clean string for display. Does NOT mutate input.
 */
export function sanitizeOptionText(text: string | undefined): string {
    if (!text) return '';

    let clean = text.trim();

    // 1. Remove specific metadata artifacts
    if (/fechamento=/i.test(clean)) {
        clean = clean.split(/fechamento=/i)[0].trim();
    }

    const METADATA_LEAK_REGEX = /(?:^|[;\s]+)(?:P[0-7]\s*[=:]|GUIA_TRAPSCAN|TRAPSCAN_EXIGIDO|WRONG_DIAGNOSIS|Erradas=|Fechamento=)[\s\S]*$/i;
    clean = clean.replace(METADATA_LEAK_REGEX, '');

    clean = clean.replace(/[;]+$/, '').trim();

    // 2. Validate resulting text content
    const lower = clean.toLowerCase();
    const invalidKeywords = ['correta', 'incorreta', '—', '-', 'nula', 'undefined', 'null'];

    if (clean.length === 0 || invalidKeywords.includes(lower)) {
        return ''; // Mark as invalid/empty
    }

    return clean;
}

/**
 * Extracts options strictly from the raw import block as a fallback.
 * Stops parsing if it hits metadata keywords to avoid false positives.
 */
function extractOptionsFromRaw(rawText: string): { [key: string]: string } {
    if (!rawText) return {};

    const lines = rawText.replace(/\r\n/g, '\n').split('\n');
    const recoveredOptions: { [key: string]: string } = {};

    // Regex anchored to start of line to avoid capturing "A:" inside sentences
    // Matches "A) Text", "A. Text", "A: Text", "A - Text"
    const optionRegex = /^\s*([A-E])\s*[:\)\-\.]\s+(.+)$/i;

    // Stop signals
    const stopRegex = /^\s*(CORRECT|ANSWER|GABARITO|EXPLANATION|COMENTARIO|DISTRACTOR_PROFILE|WRONG_DIAGNOSIS)/i;

    let inMetadataZone = false;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue;

        // Stop if we hit metadata
        if (stopRegex.test(trimmed)) {
            inMetadataZone = true;
            continue; 
        }

        // If we are in metadata zone, we stop looking for options to prevent leaks
        // UNLESS the block structure is chaotic, but for safety we stop.
        if (inMetadataZone) continue;

        const match = trimmed.match(optionRegex);
        if (match) {
            const key = match[1].toUpperCase();
            const content = match[2].trim();

            // Basic sanity check on content length
            if (content.length > 0 && !content.toLowerCase().startsWith('correta')) {
                 recoveredOptions[key] = sanitizeOptionText(content);
            }
        }
    }

    return recoveredOptions;
}

/**
 * Returns a SAFE view of the question.
 * 1. Creates a shallow copy (does NOT mutate original).
 * 2. Checks if options are missing/broken.
 * 3. Attempts to recover missing options from rawImportBlock.
 * 4. Returns the object with the best possible data for display.
 */
export function getSafeQuestionView(question: Question): Question {
    // 1. Shallow clone to prevent mutation of the persistent object
    const safeView = { ...question, options: { ...question.options } };

    // 2. Identify missing keys
    const requiredKeys = ['A', 'B', 'C', 'D', 'E'];
    const missingKeys = requiredKeys.filter(key => {
        const val = safeView.options[key];
        return !val || val.trim() === '' || val === '—';
    });

    // 3. Fallback Recovery Strategy
    if (missingKeys.length > 0 && question.rawImportBlock) {
        const recovered = extractOptionsFromRaw(question.rawImportBlock);

        missingKeys.forEach(key => {
            if (recovered[key]) {
                // Apply recovered text only to the view
                safeView.options[key] = recovered[key];
            }
        });
    }

    return safeView;
}

/**
 * Robust parser to extract options from raw text.
 * Uses strict state machine to prevent reading options from Explanation blocks.
 */
export function parseQuestionText(rawText: string): ParsedQuestionContent {
    if (!rawText) return { stem: '', options: {} };

    const lines = rawText.replace(/\r\n/g, '\n').split('\n');

    const stemLines: string[] = [];
    const options: { [key: string]: string } = {};
    let currentKey: string | null = null;

    let isParsingOptions = false;
    let hasHitMetadata = false;

    const optionStartRegex = /^\s*([A-E])\s*[:\)\-\.]\s+(.*)/i;
    const stopRegex = /^\s*(CORRECT|ANSWER|GABARITO|EXPLANATION|COMENTARIO|EXPLANATION_TECH|DISTRACTOR_PROFILE|WRONG_DIAGNOSIS|GUIA_TRAPSCAN|P[0-9]=|Erradas=|Fechamento=)/i;

    const hasExplicitHeader = /^\s*(Q_TEXT|QUESTION_TEXT|ENUNCIADO)/i.test(lines[0]);
    if (!hasExplicitHeader) {
        isParsingOptions = true; 
    }

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue;

        if (stopRegex.test(trimmed)) {
            hasHitMetadata = true;
            isParsingOptions = false;
            continue; 
        }

        if (/^\s*(Q_TEXT|QUESTION_TEXT|ENUNCIADO)[:=]/i.test(trimmed)) {
            isParsingOptions = true;
            stemLines.push(trimmed.replace(/^\s*(Q_TEXT|QUESTION_TEXT|ENUNCIADO)[:=]\s*/i, ''));
            continue;
        }

        if (hasHitMetadata) continue;

        const match = trimmed.match(optionStartRegex);

        if (match) {
            const key = match[1].toUpperCase();
            const content = match[2].trim();

            if (['A','B','C','D','E'].includes(key)) {
                if (content.toLowerCase() === 'correta' || content.toLowerCase() === 'incorreta') {
                    continue; 
                }
                currentKey = key;
                options[key] = content;
                isParsingOptions = true;
                continue;
            }
        }

        if (currentKey && isParsingOptions) {
            options[currentKey] += '\n' + trimmed;
        } else if (isParsingOptions) {
            stemLines.push(trimmed);
        }
    }

    const cleanedOptions: any = {};
    Object.keys(options).forEach(k => {
        const sanitized = sanitizeOptionText(options[k]);
        if (sanitized) {
            cleanedOptions[k] = sanitized;
        }
    });

    return { stem: stemLines.join('\n').trim(), options: cleanedOptions };
}

/**
 * Ensures a Question object has its options parsed and valid.
 * IMPORTANT: This function modifies the object for storage purposes. 
 * For display purposes without mutation, use getSafeQuestionView.
 */
export function ensureQuestionOptions(q: Question): Question {
    // 1. Check existing options for corruption
    let isCorrupted = false;

    if (q.options) {
        const values = Object.values(q.options);
        const hasBadValue = values.some(v => {
            if (!v) return false;
            const l = v.toLowerCase().trim();
            return l === 'correta' || l === 'incorreta' || l.includes('erradas=') || l.includes('fechamento=');
        });

        if (hasBadValue) {
            isCorrupted = true;
        }
    }

    // 2. If valid and not corrupted, return sanitized version
    if (!isCorrupted && q.options) {
        const cleaned: any = {};
        let hasChanges = false;

        Object.keys(q.options).forEach(k => {
            // @ts-ignore
            const val = q.options[k];
            const cleanVal = sanitizeOptionText(val);
            if (val !== cleanVal) hasChanges = true;
            if (cleanVal) {
                cleaned[k] = cleanVal;
            }
        });

        if (hasChanges) {
             return { ...q, options: cleaned };
        }
    }

    // 3. Re-parse from Raw Text (Fallback or Repair)
    const sourceText = q.rawImportBlock || q.questionText;
    const { stem, options } = parseQuestionText(sourceText);

    if (Object.keys(options).length >= 2) {
        return {
            ...q,
            questionText: stem || q.questionText, 
            options: { ...options } 
        };
    }

    return q;
}

import React, { useMemo } from 'react';
import { Question, EvidenceItem } from '../types';
import { CheckCircleIcon, XCircleIcon, LockClosedIcon, TrashIcon, ScaleIcon, ExclamationTriangleIcon } from './icons';
import QuestionExplanationBlocks from './QuestionExplanationBlocks';
import PromptText from './ui/PromptText';
import { getSafeQuestionView, sanitizeOptionText } from '../services/questionParser';

interface QuestionViewerProps {
    question: Question;
    selectedOption: string | null;
    isRevealed: boolean;
    onOptionSelect?: (key: string) => void;
    className?: string;
    showMedia?: boolean;
    isLocked?: boolean; 

    eliminatedOptions?: string[];
    onEliminate?: (key: string) => void;
    isEliminationMode?: boolean;
    highlightText?: string;

    evidence?: { stem: EvidenceItem[], options: Record<string, EvidenceItem[]> } | undefined;
    orderedKeys?: string[]; 
}

const QuestionViewer: React.FC<QuestionViewerProps> = ({ 
    question, 
    selectedOption, 
    isRevealed, 
    onOptionSelect, 
    className = "",
    showMedia = true,
    isLocked = false,
    eliminatedOptions = [],
    onEliminate,
    isEliminationMode = false,
    highlightText,
    evidence,
    orderedKeys
}) => {

    // --- SAFE VIEW LAYER ---
    // Create a safe, non-mutated view of the question where we try to recover 
    // any missing options from the raw block.
    const safeQuestion = useMemo(() => getSafeQuestionView(question), [question]);

    const handleOptionClick = (key: string) => {
        if (isLocked) return;

        if (isEliminationMode && onEliminate) {
            onEliminate(key);
            return;
        }

        if (eliminatedOptions.includes(key)) return;

        if (!isRevealed && onOptionSelect) {
            onOptionSelect(key);
        }
    };

    // Detect if this should be rendered as a Gap/Cloze question
    const isGapMode = useMemo(() => {
        if (safeQuestion.isGapType) return true;
        const text = safeQuestion.questionText || '';
        return /\{\{.+?\}\}|_{3,}/.test(text);
    }, [safeQuestion]);

    // Detect if this is a True/False (Certo/Errado) Judgement question
    const isJudgementMode = useMemo(() => {
        if (isGapMode) return false;
        const type = (safeQuestion.questionType || '').toUpperCase();
        const bank = (safeQuestion.bank || '').toUpperCase();

        // Explicit Type or Bank detection
        if (type.includes('C/E') || type.includes('CERTO') || type.includes('JULGAMENTO') || type.includes('V/F')) return true;
        if (bank.includes('CESPE') || bank.includes('CEBRASPE')) return true;

        // Content detection
        const optValues = Object.values(safeQuestion.options || {}).map(v => ((v as string) || '').trim().toUpperCase());
        if (optValues.includes('CERTO') && optValues.includes('ERRADO')) return true;

        return false;
    }, [safeQuestion, isGapMode]);

    // Resolve keys for Certo and Errado
    const judgementKeys = useMemo(() => {
        if (!isJudgementMode) return null;
        let rightKey = '';
        let wrongKey = '';

        Object.entries(safeQuestion.options || {}).forEach(([k, v]) => {
            const val = ((v as string) || '').toUpperCase().trim();
            if (val === 'CERTO') rightKey = k;
            if (val === 'ERRADO') wrongKey = k;
        });

        if (!rightKey || !wrongKey) {
            if (safeQuestion.options['C'] && !safeQuestion.options['A']) {
                rightKey = 'C'; wrongKey = 'E';
            } else {
                rightKey = 'A'; wrongKey = 'B';
            }
        }

        return { rightKey, wrongKey };
    }, [isJudgementMode, safeQuestion.options]);

    const renderQuestionText = () => {
        if (!isGapMode && highlightText && safeQuestion.questionText.includes(highlightText)) {
            const parts = safeQuestion.questionText.split(highlightText);
            return (
                <span>
                    {parts.map((part, i) => (
                        <React.Fragment key={i}>
                            <PromptText text={part} className="inline" />
                            {i < parts.length - 1 && (
                                <span className="bg-sky-500/30 text-white px-1 rounded animate-pulse font-bold border-b-2 border-sky-500">
                                    {highlightText}
                                </span>
                            )}
                        </React.Fragment>
                    ))}
                </span>
            );
        }

        return (
            <PromptText 
                text={safeQuestion.questionText} 
                mode={isGapMode ? 'gap' : 'plain'}
                revealExpected={isRevealed}
                highlights={evidence?.stem} 
            />
        );
    };

    // Calculate options from SAFE VIEW
    const optionsState = useMemo(() => {
        const ALL_KEYS = ['A', 'B', 'C', 'D', 'E'];

        return ALL_KEYS.map(key => {
            const raw = safeQuestion.options[key];
            const clean = sanitizeOptionText(raw as string);
            const isValid = clean.length > 0;
            return { 
                key, 
                text: isValid ? clean : "(Alternativa vazia ou inválida - Verifique o cadastro)", 
                isDisabled: !isValid 
            };
        });
    }, [safeQuestion.options]);

    // Check if the correct answer points to a disabled option
    const isCorrectAnswerInvalid = useMemo(() => {
        if (isJudgementMode) return false;
        const correctOpt = optionsState.find(o => o.key === safeQuestion.correctAnswer);
        return correctOpt ? correctOpt.isDisabled : true; 
    }, [optionsState, safeQuestion.correctAnswer, isJudgementMode]);

    return (
        <div className={`space-y-6 pb-10 ${className}`}>
            <div id="question-start-anchor" className="h-px w-full -mt-2"></div>

            {showMedia && (safeQuestion.questionImage || safeQuestion.questionAudio) && (
                <div className="flex flex-col gap-4 mb-4">
                    {safeQuestion.questionImage && <img src={safeQuestion.questionImage} alt="Questão" className="max-w-full rounded-lg max-h-80 object-contain mx-auto bg-black/20" />}
                    {safeQuestion.questionAudio && <audio controls src={safeQuestion.questionAudio} className="w-full" />}
                </div>
            )}

            {/* Warning Banner for Broken Data */}
            {isCorrectAnswerInvalid && !isJudgementMode && (
                <div className="bg-rose-500/10 border border-rose-500/20 p-3 rounded-lg flex items-center gap-3 animate-fade-in mb-4">
                    <ExclamationTriangleIcon className="w-5 h-5 text-rose-500" />
                    <p className="text-xs text-rose-200">
                        <strong>Atenção:</strong> O gabarito desta questão ({safeQuestion.correctAnswer}) aponta para uma alternativa inválida ou vazia. O fallback de recuperação falhou.
                    </p>
                </div>
            )}

            {/* Question Text */}
            <div className="text-base md:text-lg font-medium leading-relaxed text-slate-200">
                {renderQuestionText()}
            </div>

            <div className="relative">
                {/* LOCKED OVERLAY */}
                {isLocked && (
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900/10 backdrop-blur-sm rounded-xl border border-white/5 animate-fade-in">
                        <div className="bg-slate-900 p-4 rounded-full shadow-2xl border border-indigo-500/50 mb-3 animate-bounce-subtle">
                            <LockClosedIcon className="w-8 h-8 text-indigo-400" />
                        </div>
                        <p className="text-sm font-bold text-white bg-slate-900/80 px-4 py-2 rounded-lg shadow-lg border border-white/10">
                            Complete o P1 e P2 para liberar
                        </p>
                    </div>
                )}

                {/* ELIMINATION MODE INDICATOR */}
                {isEliminationMode && !isLocked && (
                    <div className="absolute -top-10 left-0 w-full flex justify-center pointer-events-none z-30">
                        <div className="bg-rose-500 text-white px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest shadow-lg animate-pulse flex items-center gap-2">
                            <TrashIcon className="w-3 h-3" /> Modo Eliminação Ativo
                        </div>
                    </div>
                )}

                {/* SPECIAL UI FOR JUDGEMENT (CERTO/ERRADO) */}
                {isJudgementMode && judgementKeys ? (
                    <div className={`grid grid-cols-2 gap-4 mt-6 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`}>
                        {/* CERTO BUTTON */}
                        <button
                            onClick={() => handleOptionClick(judgementKeys.rightKey)}
                            disabled={isRevealed || isLocked}
                            className={`
                                relative p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-[0.98]
                                ${isRevealed
                                    ? (safeQuestion.correctAnswer === judgementKeys.rightKey 
                                        ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' 
                                        : (selectedOption === judgementKeys.rightKey ? 'bg-rose-500/20 border-rose-500 text-rose-400' : 'bg-white/5 border-white/5 text-slate-500 opacity-50'))
                                    : (selectedOption === judgementKeys.rightKey
                                        ? 'bg-sky-600 border-sky-500 text-white shadow-lg'
                                        : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-emerald-500/50 text-slate-300')
                                }
                            `}
                        >
                            <CheckCircleIcon className="w-8 h-8 mb-1" />
                            <span className="text-lg font-black uppercase tracking-widest">Certo</span>
                        </button>

                        {/* ERRADO BUTTON */}
                        <button
                            onClick={() => handleOptionClick(judgementKeys.wrongKey)}
                            disabled={isRevealed || isLocked}
                            className={`
                                relative p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-[0.98]
                                ${isRevealed
                                    ? (safeQuestion.correctAnswer === judgementKeys.wrongKey 
                                        ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' 
                                        : (selectedOption === judgementKeys.wrongKey ? 'bg-rose-500/20 border-rose-500 text-rose-400' : 'bg-white/5 border-white/5 text-slate-500 opacity-50'))
                                    : (selectedOption === judgementKeys.wrongKey
                                        ? 'bg-sky-600 border-sky-500 text-white shadow-lg'
                                        : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-rose-500/50 text-slate-300')
                                }
                            `}
                        >
                            <XCircleIcon className="w-8 h-8 mb-1" />
                            <span className="text-lg font-black uppercase tracking-widest">Errado</span>
                        </button>

                        {/* Judgement Label */}
                        <div className="col-span-2 text-center mt-2">
                             <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em] flex items-center justify-center gap-2">
                                <ScaleIcon className="w-3 h-3" /> Julgue o Item
                             </span>
                        </div>
                    </div>
                ) : (
                    /* STANDARD MULTIPLE CHOICE UI */
                    <div className={`space-y-2 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`} id="answers-block">
                        {optionsState.map(({ key, text, isDisabled }, index) => {
                            const isEliminated = eliminatedOptions.includes(key);
                            const isSelected = selectedOption === key;
                            const isCorrect = safeQuestion.correctAnswer === key;
                            const highlights = evidence?.options[key]; 

                            const visualLabel = String.fromCharCode(65 + index); // A, B, C... (Fixed Order)

                            let btnClass = "w-full text-left p-3.5 rounded-xl border-2 transition-all flex gap-3 items-start group ";

                            // Style Logic
                            if (isDisabled) {
                                // Invalid Option State
                                btnClass += "bg-black/20 border-white/5 text-slate-600 cursor-not-allowed italic opacity-70";
                            } else if (isEliminated) {
                                btnClass += "bg-slate-900/50 border-transparent opacity-40 grayscale decoration-slate-500 line-through cursor-not-allowed";
                            } else if (isRevealed) {
                                if (isCorrect) {
                                    btnClass += "bg-emerald-500/20 border-emerald-500 text-emerald-100";
                                } else if (isSelected) {
                                    btnClass += "bg-rose-500/20 border-rose-500 text-rose-100";
                                } else {
                                    btnClass += "bg-white/5 border-white/5 opacity-50";
                                }
                            } else {
                                if (isEliminationMode) {
                                    btnClass += "bg-white/5 border-rose-500/30 hover:bg-rose-500/10 hover:border-rose-500 text-slate-300 cursor-crosshair";
                                } else if (isSelected) {
                                    btnClass += "bg-sky-600 border-sky-500 text-white shadow-lg";
                                } else {
                                    btnClass += "bg-white/5 border-white/10 hover:border-sky-500/30 hover:bg-white/10 active:scale-[0.99]";
                                }
                            }

                            return (
                                <button
                                    key={key}
                                    onClick={() => !isDisabled && handleOptionClick(key)}
                                    disabled={isDisabled || isRevealed || (isLocked)}
                                    className={btnClass}
                                    title={isDisabled ? "Opção inválida ou vazia no cadastro." : undefined}
                                >
                                    <strong className={`shrink-0 text-base ${!isDisabled && !isRevealed && !isSelected && !isEliminated ? 'text-sky-500 group-hover:text-sky-400' : 'text-current'}`}>{visualLabel})</strong>
                                    <span className="leading-snug pt-0.5 text-sm md:text-base w-full">
                                        <PromptText text={text} highlights={highlights} />
                                    </span>
                                    {isDisabled && <ExclamationTriangleIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                                    {isRevealed && isCorrect && <CheckCircleIcon className="w-5 h-5 ml-auto shrink-0 text-emerald-400" />}
                                    {isRevealed && isSelected && !isCorrect && <XCircleIcon className="w-5 h-5 ml-auto shrink-0 text-rose-400" />}
                                    {!isRevealed && isEliminated && <TrashIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                                </button>
                            );
                        })}
                    </div>
                )}
            </div>

            {isRevealed && (
                <div className="animate-fade-in pt-6 border-t border-white/10">
                   <QuestionExplanationBlocks 
                        question={safeQuestion} 
                        userAnswer={selectedOption} 
                        showTitle={true}
                   />
                </div>
            )}
        </div>
    );
};

export default QuestionViewer;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Question, TrapscanEntry, TrapscanSessionConfig } from '../types';
import { useSettings } from '../contexts/SettingsContext';
import * as trapscanLogic from '../services/trapscanLogic';
import { 
    XMarkIcon, LockClosedIcon, ArrowRightIcon, 
    ExclamationTriangleIcon, FullScreenIcon, ExitFullScreenIcon
} from './icons';
import QuestionViewer from './QuestionViewer';
import TrapscanGate from './TrapscanGate';
import QuestionActionsMenu, { QuestionContextType } from './QuestionActionsMenu';
import ReadingContainer from './ui/ReadingContainer';
import { getText } from '../utils/i18nText';
import { isStrictQuestion } from '../services/contentGate';
import ConfirmationModal from './ConfirmationModal';
import { useQuestionDispatch } from '../contexts/QuestionContext';
import { getSafeQuestionView } from '../services/questionParser';

interface QuestionRunnerProps {
    question: Question;
    sessionConfig?: TrapscanSessionConfig | null;
    onResult: (rating: 'again' | 'hard' | 'good' | 'easy', timeTaken: number, trapscanData?: TrapscanEntry) => void;
    onNext?: () => void;
    isLast?: boolean;
    onClose?: () => void;
    context: QuestionContextType;
    mode?: 'SRS' | 'SIMPLE';
    allowGaps?: boolean;
    onEdit?: (q: Question) => void;
    onDelete?: (id: string) => void;
}

const MediaBlock: React.FC<{ image?: string, audio?: string }> = ({ image, audio }) => {
    if (!image && !audio) return null;
    return (
        <div className="flex flex-col gap-3 items-center mb-6 w-full animate-fade-in" onClick={e => e.stopPropagation()}>
           {image && (
               <img src={image} alt="Mídia da Questão" className="max-w-full max-h-72 rounded-2xl shadow-2xl object-contain bg-black/20" />
           )}
           {audio && (
               <audio controls src={audio} className="w-full max-w-md h-10 opacity-90 hover:opacity-100 transition-opacity" />
           )}
        </div>
    );
};

const QuestionRunner: React.FC<QuestionRunnerProps> = ({ 
    question, 
    sessionConfig, 
    onResult, 
    onNext, 
    isLast, 
    onClose, 
    context, 
    mode = 'SRS',
    allowGaps = false,
    onEdit,
    onDelete
}) => {
    const { settings, updateSettings, addXp } = useSettings();
    const { deleteQuestions, registerAttempt } = useQuestionDispatch();
    const scrollRef = useRef<HTMLDivElement>(null);
    const startTimeRef = useRef<number>(Date.now());
    const [toastMessage, setToastMessage] = useState<string | null>(null);

    const isInvalidContent = !allowGaps && !isStrictQuestion(question);

    // --- INTEGRITY CHECK ---
    // Check if the SAFE VIEW is playable. 
    // It's unplayable if the correct answer points to an empty option.
    const safeView = useMemo(() => getSafeQuestionView(question), [question]);

    // Check if it's C/E type first (usually safe as it doesn't need text options)
    const isJudgement = safeView.questionType?.includes('C/E') || (safeView.bank?.includes('CESPE'));

    // Check if standard options are broken
    const isBroken = useMemo(() => {
        if (allowGaps || isJudgement) return false;

        const correctKey = safeView.correctAnswer;
        // @ts-ignore
        const optionText = safeView.options[correctKey];

        // If option text for correct answer is missing, it's broken.
        return !optionText || optionText.trim().length === 0;
    }, [safeView, allowGaps, isJudgement]);

    useEffect(() => {
        if (isInvalidContent || isBroken) {
            const reason = isBroken ? "Gabarito aponta para alternativa vazia" : "Conteúdo inválido/incompleto";
            console.warn(`[QuestionRunner] Skipped broken question (${question.id}). Reason: ${reason}`);

            // Show toast and auto-skip
            setToastMessage(`Questão pulada: ${reason}`);

            if (onNext) {
                const t = setTimeout(() => {
                    setToastMessage(null);
                    onNext();
                }, 2000); // 2s delay to read toast
                return () => clearTimeout(t);
            }
        }
    }, [question.id, isInvalidContent, isBroken, onNext]);

    const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

    if (isInvalidContent || isBroken) {
        return (
            <div className="flex flex-col items-center justify-center h-full p-10 text-center space-y-4 bg-slate-900 z-50 fixed inset-0">
                <ExclamationTriangleIcon className="w-16 h-16 text-amber-500 animate-pulse" />
                <h3 className="text-xl font-bold text-white">Conteúdo Corrompido</h3>
                <p className="text-slate-400 text-sm max-w-xs">{toastMessage || "Detectando integridade..."}</p>
                <div className="w-8 h-8 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
                <button onClick={onNext} className="mt-4 text-xs text-slate-500 hover:text-white underline">
                    Forçar Avanço Imediato
                </button>
            </div>
        );
    }

    const activeConfig: TrapscanSessionConfig = useMemo(() => {
        if (sessionConfig) return sessionConfig;
        const defaults = { enabled: true, assistMode: true, defaultMode: 'TREINO' as const, lockLevel: 'SOFT' as const };
        return (settings.trapscan as TrapscanSessionConfig) || defaults;
    }, [sessionConfig, settings.trapscan]);

    const [selectedOption, setSelectedOption] = useState<string | null>(null);
    const [isRevealed, setIsRevealed] = useState(false);
    const [trapscanData, setTrapscanData] = useState<TrapscanEntry | undefined>(undefined);
    const [showBlockToast, setShowBlockToast] = useState<string | null>(null);

    const [eliminatedOptions, setEliminatedOptions] = useState<string[]>([]);
    const [isEliminationMode, setIsEliminationMode] = useState(false);
    const [highlightAnchor, setHighlightAnchor] = useState(false);

    useEffect(() => {
        setSelectedOption(null);
        setIsRevealed(false);
        setTrapscanData(undefined);
        setEliminatedOptions([]);
        setIsEliminationMode(false);
        setHighlightAnchor(false);
        setIsDeleteConfirmOpen(false);
        startTimeRef.current = Date.now();
        setToastMessage(null);

        if (scrollRef.current) {
            scrollRef.current.scrollTo({ top: 0, behavior: 'instant' });
        }
    }, [question.id]);

    const isGap = allowGaps && (question.isGapType || question.questionText.includes('{{'));
    const isLocked = !isGap && trapscanLogic.checkAlternativesLocked(activeConfig, trapscanData);
    const blockReason = !isGap ? trapscanLogic.getSubmitBlockReason(activeConfig, trapscanData, !!selectedOption) : null;
    const canSubmit = !blockReason;

    const handleOptionSelect = (key: string) => {
        if (!isRevealed && !isLocked && !isEliminationMode) {
            setSelectedOption(key);
        }
    };

    const handleEliminate = (key: string) => {
        setEliminatedOptions(prev => {
             if (prev.includes(key)) return prev.filter(k => k !== key);
             return [...prev, key];
        });
    };

    const handleReveal = () => {
        if (!canSubmit) {
            setShowBlockToast(blockReason);
            setTimeout(() => setShowBlockToast(null), 3000);
            return;
        }
        setIsRevealed(true);
    };

    const handleRating = (rating: 'again' | 'hard' | 'good' | 'easy') => {
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // No orderKeys passed (shuffle disabled)
        onResult(rating, timeTaken, trapscanData);
        if (onNext) onNext();
    };

    const handleSimpleNext = () => {
        const isCorrect = selectedOption === question.correctAnswer;
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // No orderKeys passed (shuffle disabled)
        onResult(isCorrect ? 'good' : 'again', timeTaken, trapscanData);
        if (onNext) onNext();
    };

    const toggleReaderMode = () => {
        const newMode = settings.readerMode === 'compact' ? 'fullscreen' : 'compact';
        updateSettings({ readerMode: newMode });
    };

    const handleDeleteRequest = (id: string) => {
        setIsDeleteConfirmOpen(true);
    };

    const handleConfirmDelete = () => {
        deleteQuestions([question.id]);
        if (onDelete) onDelete(question.id);
        if (onNext) onNext();
        setIsDeleteConfirmOpen(false);
    };

    const showTrapscan = !isGap && trapscanLogic.isTrapscanActive(activeConfig) && !question.isGapType;

    return (
        <div className="flex flex-col h-full bg-[var(--q-surface)] text-[var(--q-text)] relative">
            <header className="px-5 py-4 border-b border-[var(--q-border)] flex justify-between items-center bg-[var(--q-surface)] backdrop-blur-md shrink-0 z-10">
                <div className="min-w-0 pr-4">
                    <h2 className="text-sm font-extrabold tracking-tight truncate uppercase italic">{question.questionRef}</h2>
                    <p className="text-[10px] font-semibold text-[var(--q-muted)] uppercase mt-0.5">{question.subject}</p>
                </div>
                <div className="flex items-center gap-2">
                    {activeConfig?.enabled && showTrapscan && (
                        <div className={`hidden sm:block px-2 py-0.5 rounded text-[9px] font-black uppercase border ${activeConfig.assistMode ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' : 'bg-slate-500/10 border-slate-500/30 text-slate-500'}`}>
                            {activeConfig.assistMode ? (activeConfig.defaultMode === 'GUIA' ? 'GUIA' : `LOCK: ${activeConfig.lockLevel}`) : 'OFF'}
                        </div>
                    )}

                    <button 
                        onClick={toggleReaderMode}
                        className="p-2 rounded-lg text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors hidden sm:block"
                        title={settings.readerMode === 'compact' ? "Expandir Tela" : "Modo Leitura"}
                    >
                        {settings.readerMode === 'compact' ? <FullScreenIcon className="w-5 h-5"/> : <ExitFullScreenIcon className="w-5 h-5"/>}
                    </button>

                    <QuestionActionsMenu 
                        question={question} 
                        context={context} 
                        onEdit={onEdit} 
                        onDelete={handleDeleteRequest} 
                    />

                    {onClose && (
                        <button onClick={onClose} className="p-2 -mr-2 text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors">
                            <XMarkIcon className="w-5 h-5"/>
                        </button>
                    )}
                </div>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar" ref={scrollRef}>
                 <ReadingContainer mode={settings.readerMode} className="py-6 pb-24 md:py-8">
                      <MediaBlock image={question.questionImage} audio={question.questionAudio} />

                      {showTrapscan && !isRevealed && (
                          <TrapscanGate 
                              question={question}
                              isLocked={isLocked}
                              onUnlock={() => {}} 
                              onAllowSubmit={() => {}} 
                              onUpdate={setTrapscanData}
                              userAnswer={selectedOption}
                              configOverride={activeConfig}
                              eliminatedOptions={eliminatedOptions}
                              onSetEliminationMode={setIsEliminationMode}
                              onSetHighlightAnchor={setHighlightAnchor}
                          />
                      )}

                      <QuestionViewer 
                          question={question}
                          selectedOption={selectedOption}
                          isRevealed={isRevealed}
                          onOptionSelect={handleOptionSelect}
                          showMedia={false} 
                          isLocked={isLocked}
                          isEliminationMode={isEliminationMode}
                          eliminatedOptions={eliminatedOptions}
                          onEliminate={handleEliminate}
                          highlightText={highlightAnchor ? getText(question.anchorText) : undefined}
                          // Remove orderedKeys to enforce stable alphabetical rendering
                          orderedKeys={undefined}
                      />
                  </ReadingContainer>
            </div>

            {showBlockToast && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 bg-rose-500 text-white px-6 py-3 rounded-full shadow-2xl font-bold text-xs uppercase tracking-widest z-50 animate-bounce-subtle flex items-center gap-2">
                    <LockClosedIcon className="w-4 h-4" />
                    {showBlockToast}
                </div>
            )}

            {toastMessage && (
                 <div className="absolute top-20 left-1/2 -translate-x-1/2 bg-amber-500 text-black px-4 py-2 rounded-lg shadow-lg font-bold text-xs uppercase z-50">
                    {toastMessage}
                 </div>
            )}

            {selectedOption && (
                <footer className="p-5 bg-[var(--q-surface)] border-t border-[var(--q-border)] shrink-0 z-20 pb-[calc(1.5rem+env(safe-area-inset-bottom))] shadow-[0_-10px_40px_rgba(0,0,0,0.3)]">
                    <ReadingContainer mode={settings.readerMode} className="!px-0">
                        {!isRevealed ? (
                            <button 
                                onClick={handleReveal} 
                                disabled={!canSubmit && activeConfig?.assistMode && activeConfig?.defaultMode === 'TREINO'}
                                className={`w-full font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-widest text-sm flex items-center justify-center gap-2
                                    ${canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA'
                                        ? 'bg-sky-600 text-white hover:bg-sky-500 active:scale-[0.98]' 
                                        : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-80'}`}
                            >
                                {(canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA') ? 'Ver Gabarito' : <><LockClosedIcon className="w-4 h-4"/> Complete o Trapscan</>}
                            </button>
                        ) : (
                            mode === 'SRS' ? (
                                <div className="grid grid-cols-4 gap-3 h-20">
                                    <button onClick={() => handleRating('again')} className="rounded-2xl bg-rose-500/10 border-2 border-rose-500/50 text-rose-500 hover:bg-rose-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Errei</span>
                                    </button>
                                    <button onClick={() => handleRating('hard')} className="rounded-2xl bg-amber-500/10 border-2 border-amber-500/50 text-amber-500 hover:bg-amber-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Difícil</span>
                                    </button>
                                    <button onClick={() => handleRating('good')} className="rounded-2xl bg-sky-500/10 border-2 border-sky-500/50 text-sky-500 hover:bg-sky-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Bom</span>
                                    </button>
                                    <button onClick={() => handleRating('easy')} className="rounded-2xl bg-emerald-500/10 border-2 border-emerald-500/50 text-emerald-500 hover:bg-emerald-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Fácil</span>
                                    </button>
                                </div>
                            ) : (
                                <button 
                                    onClick={handleSimpleNext} 
                                    className={`w-full font-black py-4 rounded-2xl shadow-xl flex items-center justify-center gap-3 uppercase tracking-widest text-xs active:scale-95 transition-all ${isLast ? 'bg-emerald-600 hover:bg-emerald-500 text-white' : 'bg-white text-slate-900 hover:bg-sky-50'}`}
                                >
                                    {isLast ? 'Finalizar' : 'Próxima'} <ArrowRightIcon className="w-4 h-4" />
                                </button>
                            )
                        )}
                    </ReadingContainer>
                </footer>
            )}

            <ConfirmationModal 
                isOpen={isDeleteConfirmOpen} 
                onClose={() => setIsDeleteConfirmOpen(false)} 
                onConfirm={handleConfirmDelete} 
                title="Excluir Questão?"
            >
                <div className="space-y-2">
                    <p className="text-sm text-slate-300">Tem certeza que deseja apagar esta questão? Ela será removida de todas as suas listas de estudo.</p>
                    <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Ação irreversível.</p>
                </div>
            </ConfirmationModal>

        </div>
    );
};

export default QuestionRunner;

import { AttemptReport, WrongItemReport, Question, Flashcard, PracticeType, SessionResult, AppSettings } from '../types';
import { saveData, loadData } from './storage';
import * as srs from './srsService';

const LS_REPORTS_KEY = 'revApp_attempt_reports_v1';
const LS_INVALID_ITEMS_KEY = 'revApp_invalid_items_v1';

export interface InvalidItemReport {
    id: string;
    questionRef: string;
    lawRef?: string;
    correctAnswer: string;
    missingOptions: string[]; // List of keys (A, B...) that are empty
    hasRawBlock: boolean;
    textSnippet: string;
    timestamp: string;
    sessionId?: string;
}

/**
 * Logs a broken question for batch correction.
 */
export async function logInvalidItem(question: Question, missingKeys: string[]): Promise<void> {
    try {
        const report: InvalidItemReport = {
            id: question.id,
            questionRef: question.questionRef,
            lawRef: question.lawRef,
            correctAnswer: question.correctAnswer,
            missingOptions: missingKeys,
            hasRawBlock: !!question.rawImportBlock,
            textSnippet: (question.questionText || '').slice(0, 200),
            timestamp: new Date().toISOString(),
            sessionId: (window as any).__MIAAULA_SESSION_ID__
        };

        const existing = await loadData<InvalidItemReport[]>(LS_INVALID_ITEMS_KEY) || [];

        // Avoid duplicate logs for the same ID
        if (!existing.some(i => i.id === report.id)) {
            const updated = [report, ...existing];
            await saveData(LS_INVALID_ITEMS_KEY, updated);
            console.warn('[ReportService] Item inválido registrado para correção:', report);
        }
    } catch (e) {
        console.error('[ReportService] Falha ao registrar item inválido:', e);
    }
}

/**
 * Salva um novo relatório de tentativa.
 */
export async function saveAttemptReport(report: AttemptReport): Promise<void> {
    try {
        const existing = await loadData<AttemptReport[]>(LS_REPORTS_KEY) || [];
        // Mantém apenas os últimos 200 relatórios para performance
        const updated = [report, ...existing].slice(0, 200);
        await saveData(LS_REPORTS_KEY, updated);
        console.log('[ReportService] Relatório salvo:', report.id);
    } catch (e) {
        console.error('[ReportService] Erro ao salvar relatório:', e);
    }
}

/**
 * Lista relatórios filtrados por aula ou trilha.
 */
export async function listReportsByLesson(lessonId: string): Promise<AttemptReport[]> {
    const all = await loadData<AttemptReport[]>(LS_REPORTS_KEY) || [];
    return all.filter(r => r.lessonId === lessonId);
}

/**
 * Faz o download de um relatório específico em formato JSON.
 */
export function downloadReportAsJson(report: AttemptReport): void {
    try {
        const dataStr = JSON.stringify(report, null, 2);
        const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);

        const date = new Date(report.finishedAt);
        const dateStr = date.toISOString().split('T')[0];
        const timeStr = date.getHours().toString().padStart(2, '0') + '-' + date.getMinutes().toString().padStart(2, '0');

        const exportFileDefaultName = `miaaula_report_${report.lessonId}_${report.practiceType}_${dateStr}_${timeStr}.json`
            .replace(/[^a-z0-9.]/gi, '_')
            .toLowerCase();

        const linkElement = document.createElement('a');
        linkElement.setAttribute('href', dataUri);
        linkElement.setAttribute('download', exportFileDefaultName);
        linkElement.click();
    } catch (e) {
        console.error('[ReportService] Erro ao exportar JSON:', e);
        alert('Erro ao gerar arquivo para download.');
    }
}

/**
 * Converte um conjunto de questões respondidas em um relatório de erros.
 */
export function buildReportFromQuestions(
    lessonId: string,
    practiceType: PracticeType,
    startedAt: Date,
    answeredQuestions: Question[]
): AttemptReport {
    const finishedAt = new Date();
    const wrongQuestions = answeredQuestions.filter(q => !q.lastWasCorrect);

    const wrongItems: WrongItemReport[] = wrongQuestions.map(q => {
        const userAns = q.yourAnswer || '-';
        const correctAns = q.correctAnswer;

        return {
            itemId: q.id,
            qRef: q.questionRef,
            text: q.questionText,
            userAnswer: userAns,
            correctAnswer: correctAns,
            userAnswerText: q.options[userAns as keyof typeof q.options] || '—',
            correctAnswerText: q.options[correctAns as keyof typeof q.options] || '—',
            explanation: q.explanation,
            wrongDiagnosis: q.wrongDiagnosis,
            subject: q.subject,
            topic: q.topic
        };
    });

    const total = answeredQuestions.length;
    const correct = total - wrongItems.length;

    return {
        id: `rep_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
        lessonId,
        practiceType,
        startedAt: startedAt.toISOString(),
        finishedAt: finishedAt.toISOString(),
        totalItems: total,
        totalCorrect: correct,
        totalWrong: wrongItems.length,
        accuracyPct: total > 0 ? Math.round((correct / total) * 100) : 0,
        durationSec: Math.round((finishedAt.getTime() - startedAt.getTime()) / 1000),
        wrongItems
    };
}

/**
 * Calcula o consolidado da sessão para o Relatório Visual de Progresso com deltas.
 */
export function calculateSessionResult(
    title: string,
    startedAt: Date,
    answeredQuestions: Question[],
    initialStates: Map<string, { mastery: number, domain: number }>,
    settings: AppSettings,
    isCompleted: boolean
): SessionResult {
    const endedAt = new Date();
    const answeredCount = answeredQuestions.length;
    const correctCount = answeredQuestions.filter(q => q.lastWasCorrect).length;
    const wrongCount = answeredCount - correctCount;

    let totalMasteryGain = 0;
    let totalDomainGain = 0;

    answeredQuestions.forEach(q => {
        const initial = initialStates.get(q.id);
        if (initial) {
            const currentDomain = srs.calculateCurrentDomain(q, settings);
            totalMasteryGain += (q.masteryScore - initial.mastery);
            totalDomainGain += (currentDomain - initial.domain);
        }
    });

    const avgMasteryGain = answeredCount > 0 ? totalMasteryGain / answeredCount : 0;
    const avgDomainGain = answeredCount > 0 ? totalDomainGain / answeredCount : 0;
    const accuracy = answeredCount > 0 ? (correctCount / answeredCount) * 100 : 0;

    return {
        id: `session_${Date.now()}`,
        title,
        startedAt: startedAt.toISOString(),
        endedAt: endedAt.toISOString(),
        totalQuestions: answeredCount,
        answeredCount,
        correctCount,
        wrongCount,
        accuracy,
        totalTimeSec: Math.round((endedAt.getTime() - startedAt.getTime()) / 1000),
        masteryGain: avgMasteryGain,
        domainGain: avgDomainGain,
        performanceScore: accuracy,
        isCompleted
    };
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Question, TrapscanEntry, TrapscanSessionConfig } from '../types';
import { useSettings } from '../contexts/SettingsContext';
import * as trapscanLogic from '../services/trapscanLogic';
import { 
    XMarkIcon, LockClosedIcon, ArrowRightIcon, 
    ExclamationTriangleIcon, FullScreenIcon, ExitFullScreenIcon,
    WrenchScrewdriverIcon
} from './icons';
import QuestionViewer from './QuestionViewer';
import TrapscanGate from './TrapscanGate';
import QuestionActionsMenu, { QuestionContextType } from './QuestionActionsMenu';
import ReadingContainer from './ui/ReadingContainer';
import { getText } from '../utils/i18nText';
import { isStrictQuestion } from '../services/contentGate';
import ConfirmationModal from './ConfirmationModal';
import { useQuestionDispatch } from '../contexts/QuestionContext';
import { getSafeQuestionView } from '../services/questionParser';
import { logInvalidItem } from '../services/reportService'; // NEW IMPORT

interface QuestionRunnerProps {
    question: Question;
    sessionConfig?: TrapscanSessionConfig | null;
    onResult: (rating: 'again' | 'hard' | 'good' | 'easy', timeTaken: number, trapscanData?: TrapscanEntry) => void;
    onNext?: () => void;
    isLast?: boolean;
    onClose?: () => void;
    context: QuestionContextType;
    mode?: 'SRS' | 'SIMPLE';
    allowGaps?: boolean;
    onEdit?: (q: Question) => void;
    onDelete?: (id: string) => void;
}

const MediaBlock: React.FC<{ image?: string, audio?: string }> = ({ image, audio }) => {
    if (!image && !audio) return null;
    return (
        <div className="flex flex-col gap-3 items-center mb-6 w-full animate-fade-in" onClick={e => e.stopPropagation()}>
           {image && (
               <img src={image} alt="Mídia da Questão" className="max-w-full max-h-72 rounded-2xl shadow-2xl object-contain bg-black/20" />
           )}
           {audio && (
               <audio controls src={audio} className="w-full max-w-md h-10 opacity-90 hover:opacity-100 transition-opacity" />
           )}
        </div>
    );
};

const QuestionRunner: React.FC<QuestionRunnerProps> = ({ 
    question, 
    sessionConfig, 
    onResult, 
    onNext, 
    isLast, 
    onClose, 
    context, 
    mode = 'SRS',
    allowGaps = false,
    onEdit,
    onDelete
}) => {
    const { settings, updateSettings, addXp } = useSettings();
    const { deleteQuestions, registerAttempt } = useQuestionDispatch();
    const scrollRef = useRef<HTMLDivElement>(null);
    const startTimeRef = useRef<number>(Date.now());
    const [toastMessage, setToastMessage] = useState<string | null>(null);

    const isInvalidContent = !allowGaps && !isStrictQuestion(question);

    // --- INTEGRITY CHECK ---
    // Check if the SAFE VIEW is playable. 
    const safeView = useMemo(() => getSafeQuestionView(question), [question]);

    // Check if it's C/E type first (usually safe as it doesn't need text options)
    const isJudgement = safeView.questionType?.includes('C/E') || (safeView.bank?.includes('CESPE'));

    // Check if standard options are broken
    const integrityCheck = useMemo(() => {
        if (allowGaps || isJudgement) return { broken: false, missing: [] };

        const correctKey = safeView.correctAnswer;
        // @ts-ignore
        const correctOptionText = safeView.options[correctKey];
        const missingKeys: string[] = [];

        ['A', 'B', 'C', 'D', 'E'].forEach(k => {
             // @ts-ignore
             if (!safeView.options[k] || !safeView.options[k].trim()) missingKeys.push(k);
        });

        // It is CRITICALLY BROKEN if the correct answer option is empty
        const isCriticalBroken = !correctOptionText || correctOptionText.trim().length === 0;

        return { broken: isCriticalBroken, missing: missingKeys };
    }, [safeView, allowGaps, isJudgement]);

    const isBroken = integrityCheck.broken;

    // --- AUTO SKIP BROKEN ITEMS ---
    useEffect(() => {
        if (isInvalidContent || isBroken) {
            // Log for batch correction
            logInvalidItem(question, integrityCheck.missing);

            // UI Feedback
            const reason = isBroken ? "Cadastro incompleto: gabarito sem texto" : "Conteúdo inválido";
            setToastMessage(`Questão enviada para correção do lote.`);

            // Auto-skip logic
            if (onNext) {
                const t = setTimeout(() => {
                    setToastMessage(null);
                    onNext();
                }, 1500); // 1.5s delay to read message
                return () => clearTimeout(t);
            }
        }
    }, [question.id, isInvalidContent, isBroken, onNext, integrityCheck.missing]);

    const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

    // --- BROKEN STATE RENDER ---
    // If broken, we still render the viewer (locked) so user sees WHAT is wrong, but overlay the warning
    const renderBrokenOverlay = () => (
        <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-sm p-6 text-center animate-fade-in">
             <WrenchScrewdriverIcon className="w-16 h-16 text-amber-500 mb-4 animate-bounce-subtle" />
             <h3 className="text-xl font-bold text-white mb-2">Item em Manutenção</h3>
             <p className="text-slate-400 text-sm max-w-xs mb-6">
                 Esta questão possui cadastro incompleto (alternativas vazias). Ela foi registrada automaticamente para correção no lote.
             </p>
             <div className="w-full h-1 bg-slate-800 rounded-full overflow-hidden max-w-xs">
                 <div className="h-full bg-amber-500 animate-progress-indeterminate"></div>
             </div>
             <p className="text-[10px] text-slate-500 mt-2 uppercase tracking-widest font-bold">Pulando...</p>
        </div>
    );

    const activeConfig: TrapscanSessionConfig = useMemo(() => {
        if (sessionConfig) return sessionConfig;
        const defaults = { enabled: true, assistMode: true, defaultMode: 'TREINO' as const, lockLevel: 'SOFT' as const };
        return (settings.trapscan as TrapscanSessionConfig) || defaults;
    }, [sessionConfig, settings.trapscan]);

    const [selectedOption, setSelectedOption] = useState<string | null>(null);
    const [isRevealed, setIsRevealed] = useState(false);
    const [trapscanData, setTrapscanData] = useState<TrapscanEntry | undefined>(undefined);
    const [showBlockToast, setShowBlockToast] = useState<string | null>(null);

    const [eliminatedOptions, setEliminatedOptions] = useState<string[]>([]);
    const [isEliminationMode, setIsEliminationMode] = useState(false);
    const [highlightAnchor, setHighlightAnchor] = useState(false);

    useEffect(() => {
        setSelectedOption(null);
        setIsRevealed(false);
        setTrapscanData(undefined);
        setEliminatedOptions([]);
        setIsEliminationMode(false);
        setHighlightAnchor(false);
        setIsDeleteConfirmOpen(false);
        startTimeRef.current = Date.now();
        setToastMessage(null);

        if (scrollRef.current) {
            scrollRef.current.scrollTo({ top: 0, behavior: 'instant' });
        }
    }, [question.id]);

    const isGap = allowGaps && (question.isGapType || question.questionText.includes('{{'));
    const isLocked = (!isGap && trapscanLogic.checkAlternativesLocked(activeConfig, trapscanData)) || isBroken; // Force lock if broken
    const blockReason = !isGap ? trapscanLogic.getSubmitBlockReason(activeConfig, trapscanData, !!selectedOption) : null;
    const canSubmit = !blockReason && !isBroken;

    const handleOptionSelect = (key: string) => {
        if (!isRevealed && !isLocked && !isEliminationMode && !isBroken) {
            setSelectedOption(key);
        }
    };

    const handleEliminate = (key: string) => {
        if (isBroken) return;
        setEliminatedOptions(prev => {
             if (prev.includes(key)) return prev.filter(k => k !== key);
             return [...prev, key];
        });
    };

    const handleReveal = () => {
        if (!canSubmit) {
            setShowBlockToast(blockReason);
            setTimeout(() => setShowBlockToast(null), 3000);
            return;
        }
        setIsRevealed(true);
    };

    const handleRating = (rating: 'again' | 'hard' | 'good' | 'easy') => {
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // No orderKeys passed (shuffle disabled)
        onResult(rating, timeTaken, trapscanData);
        if (onNext) onNext();
    };

    const handleSimpleNext = () => {
        const isCorrect = selectedOption === question.correctAnswer;
        const timeTaken = (Date.now() - startTimeRef.current) / 1000;
        // No orderKeys passed (shuffle disabled)
        onResult(isCorrect ? 'good' : 'again', timeTaken, trapscanData);
        if (onNext) onNext();
    };

    const toggleReaderMode = () => {
        const newMode = settings.readerMode === 'compact' ? 'fullscreen' : 'compact';
        updateSettings({ readerMode: newMode });
    };

    const handleDeleteRequest = (id: string) => {
        setIsDeleteConfirmOpen(true);
    };

    const handleConfirmDelete = () => {
        deleteQuestions([question.id]);
        if (onDelete) onDelete(question.id);
        if (onNext) onNext();
        setIsDeleteConfirmOpen(false);
    };

    const showTrapscan = !isGap && trapscanLogic.isTrapscanActive(activeConfig) && !question.isGapType && !isBroken;

    return (
        <div className="flex flex-col h-full bg-[var(--q-surface)] text-[var(--q-text)] relative">

            {/* Auto-Skip Overlay for Broken Items */}
            {(isBroken || isInvalidContent) && renderBrokenOverlay()}

            <header className="px-5 py-4 border-b border-[var(--q-border)] flex justify-between items-center bg-[var(--q-surface)] backdrop-blur-md shrink-0 z-10">
                <div className="min-w-0 pr-4">
                    <h2 className="text-sm font-extrabold tracking-tight truncate uppercase italic">{question.questionRef}</h2>
                    <p className="text-[10px] font-semibold text-[var(--q-muted)] uppercase mt-0.5">{question.subject}</p>
                </div>
                <div className="flex items-center gap-2">
                    {activeConfig?.enabled && showTrapscan && (
                        <div className={`hidden sm:block px-2 py-0.5 rounded text-[9px] font-black uppercase border ${activeConfig.assistMode ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' : 'bg-slate-500/10 border-slate-500/30 text-slate-500'}`}>
                            {activeConfig.assistMode ? (activeConfig.defaultMode === 'GUIA' ? 'GUIA' : `LOCK: ${activeConfig.lockLevel}`) : 'OFF'}
                        </div>
                    )}

                    <button 
                        onClick={toggleReaderMode}
                        className="p-2 rounded-lg text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors hidden sm:block"
                        title={settings.readerMode === 'compact' ? "Expandir Tela" : "Modo Leitura"}
                    >
                        {settings.readerMode === 'compact' ? <FullScreenIcon className="w-5 h-5"/> : <ExitFullScreenIcon className="w-5 h-5"/>}
                    </button>

                    <QuestionActionsMenu 
                        question={question} 
                        context={context} 
                        onEdit={onEdit} 
                        onDelete={handleDeleteRequest} 
                    />

                    {onClose && (
                        <button onClick={onClose} className="p-2 -mr-2 text-[var(--q-muted)] hover:bg-[var(--q-hover)] transition-colors">
                            <XMarkIcon className="w-5 h-5"/>
                        </button>
                    )}
                </div>
            </header>

            <div className="flex-1 overflow-y-auto custom-scrollbar" ref={scrollRef}>
                 <ReadingContainer mode={settings.readerMode} className="py-6 pb-24 md:py-8">
                      <MediaBlock image={question.questionImage} audio={question.questionAudio} />

                      {showTrapscan && !isRevealed && (
                          <TrapscanGate 
                              question={question}
                              isLocked={isLocked}
                              onUnlock={() => {}} 
                              onAllowSubmit={() => {}} 
                              onUpdate={setTrapscanData}
                              userAnswer={selectedOption}
                              configOverride={activeConfig}
                              eliminatedOptions={eliminatedOptions}
                              onSetEliminationMode={setIsEliminationMode}
                              onSetHighlightAnchor={setHighlightAnchor}
                          />
                      )}

                      <QuestionViewer 
                          question={question}
                          selectedOption={selectedOption}
                          isRevealed={isRevealed}
                          onOptionSelect={handleOptionSelect}
                          showMedia={false} 
                          isLocked={isLocked} // Will be true if broken
                          isEliminationMode={isEliminationMode}
                          eliminatedOptions={eliminatedOptions}
                          onEliminate={handleEliminate}
                          highlightText={highlightAnchor ? getText(question.anchorText) : undefined}
                          // Remove orderedKeys to enforce stable alphabetical rendering
                          orderedKeys={undefined}
                      />
                  </ReadingContainer>
            </div>

            {showBlockToast && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 bg-rose-500 text-white px-6 py-3 rounded-full shadow-2xl font-bold text-xs uppercase tracking-widest z-50 animate-bounce-subtle flex items-center gap-2">
                    <LockClosedIcon className="w-4 h-4" />
                    {showBlockToast}
                </div>
            )}

            {toastMessage && (
                 <div className="absolute top-20 left-1/2 -translate-x-1/2 bg-amber-500 text-black px-4 py-2 rounded-lg shadow-lg font-bold text-xs uppercase z-50 animate-fade-in-up">
                    {toastMessage}
                 </div>
            )}

            {selectedOption && (
                <footer className="p-5 bg-[var(--q-surface)] border-t border-[var(--q-border)] shrink-0 z-20 pb-[calc(1.5rem+env(safe-area-inset-bottom))] shadow-[0_-10px_40px_rgba(0,0,0,0.3)]">
                    <ReadingContainer mode={settings.readerMode} className="!px-0">
                        {!isRevealed ? (
                            <button 
                                onClick={handleReveal} 
                                disabled={!canSubmit && activeConfig?.assistMode && activeConfig?.defaultMode === 'TREINO'}
                                className={`w-full font-black py-4 rounded-2xl shadow-xl transition-all uppercase tracking-widest text-sm flex items-center justify-center gap-2
                                    ${canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA'
                                        ? 'bg-sky-600 text-white hover:bg-sky-500 active:scale-[0.98]' 
                                        : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-80'}`}
                            >
                                {(canSubmit || !activeConfig?.assistMode || activeConfig?.defaultMode === 'GUIA') ? 'Ver Gabarito' : <><LockClosedIcon className="w-4 h-4"/> Complete o Trapscan</>}
                            </button>
                        ) : (
                            mode === 'SRS' ? (
                                <div className="grid grid-cols-4 gap-3 h-20">
                                    <button onClick={() => handleRating('again')} className="rounded-2xl bg-rose-500/10 border-2 border-rose-500/50 text-rose-500 hover:bg-rose-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Errei</span>
                                    </button>
                                    <button onClick={() => handleRating('hard')} className="rounded-2xl bg-amber-500/10 border-2 border-amber-500/50 text-amber-500 hover:bg-amber-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Difícil</span>
                                    </button>
                                    <button onClick={() => handleRating('good')} className="rounded-2xl bg-sky-500/10 border-2 border-sky-500/50 text-sky-500 hover:bg-sky-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Bom</span>
                                    </button>
                                    <button onClick={() => handleRating('easy')} className="rounded-2xl bg-emerald-500/10 border-2 border-emerald-500/50 text-emerald-500 hover:bg-emerald-500 hover:text-white font-black text-xs uppercase tracking-widest transition-all active:scale-95 flex flex-col items-center justify-center gap-1 shadow-sm">
                                        <span>Fácil</span>
                                    </button>
                                </div>
                            ) : (
                                <button 
                                    onClick={handleSimpleNext} 
                                    className={`w-full font-black py-4 rounded-2xl shadow-xl flex items-center justify-center gap-3 uppercase tracking-widest text-xs active:scale-95 transition-all ${isLast ? 'bg-emerald-600 hover:bg-emerald-500 text-white' : 'bg-white text-slate-900 hover:bg-sky-50'}`}
                                >
                                    {isLast ? 'Finalizar' : 'Próxima'} <ArrowRightIcon className="w-4 h-4" />
                                </button>
                            )
                        )}
                    </ReadingContainer>
                </footer>
            )}

            <ConfirmationModal 
                isOpen={isDeleteConfirmOpen} 
                onClose={() => setIsDeleteConfirmOpen(false)} 
                onConfirm={handleConfirmDelete} 
                title="Excluir Questão?"
            >
                <div className="space-y-2">
                    <p className="text-sm text-slate-300">Tem certeza que deseja apagar esta questão? Ela será removida de todas as suas listas de estudo.</p>
                    <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest">Ação irreversível.</p>
                </div>
            </ConfirmationModal>

        </div>
    );
};

