export interface ImportResult {
    batchId: string;
    cards: LiteralnessCard[];
    questions: Question[];
    flashcards: Flashcard[];
    gaps: any[]; 
    stats: {
        cards: number;
        questions: number;
        flashcards: number;
        pairs: number;
        gaps: number;
    };
