}

// --- HELPER: Parse Map String to Object ---
const parseMapString = (data: string): Record<string, string> => {
    const result: Record<string, string> = {};
    if (!data || typeof data !== 'string') return result;

    // Support | or || separators
    const parts = data.includes('||') ? data.split('||') : data.split('|');
    parts.forEach(p => {
        const match = p.trim().match(/^([A-E])\s*[:=]\s*(.*)$/);
        if (match) {
            result[match[1]] = match[2].trim();
        }
    });
    return result;
};


/**
 * MIIAULA ROBUST PARSER (PATCH 1.6 - FEEDBACK ENGINE & FLEXIBLE KEYS)
 */
export const parseOfficialStrict = (text: string, settings: AppSettings): { 
    batchId: string, 
    nuclei: any[], 
    contents: any[],
    reports: ImportReport[] 
} => {
    const batchId = `BATCH_${Date.now()}`;
    const nuclei: any[] = [];
    const contents: any[] = [];
    const reports: ImportReport[] = [];

    // Regex expandido para incluir campos do Feedback Engine com suporte a variações
    const KEY_REGEX = /\b(LIT_REF|LAW_ID|ARTICLE|TOPIC|PHASE1_FULL|PARTS_SUMMARY|RESUMO_POR_PARTES|KEYWORDS_PROVA|RISCO_FCC|GANCHO_MNEMONICO|STORYTELLING|FEYNMAN|PHASE3_ORIGINAL|PHASE3_VARIANT|EXPLAIN|PHASE2_LACUNA_\d+|PHASE2_CORRECT_\d+|PHASE2_OPT_[A-E]_\d+|Q_REF|Q_TEXT|QUESTION_TEXT|CORRECT|ANSWER|A|B|C|D|E|FC_REF|PAIR_REF|TOPIC_TITLE|FRONT|BACK|TAGS|LAW_REF|GUIA_TRAPSCAN|TRAPSCAN|PALAVRA_QUE_SALVA|KEY_DISTINCTION|FRASE_ANCORA_FINAL|FRASE_ANCORA|ANCHOR_TEXT|EXPLANATION_TECH|EXPLICA_TECNICA|EXPLANATION_STORY|HISTORIA|PERGUNTAS_FEYNMAN|DISTRACTOR_PROFILE|PERFIL_DISTRATORES|WRONG_DIAGNOSIS|DIAGNOSTICO_ERRO|WRONG_DIAGNOSIS_MAP|MAPA_ERRO|EXPLANATION|COMENTARIO):\s*/g;

    const keyPositions: { key: string, start: number, end: number }[] = [];
    let match;
    while ((match = KEY_REGEX.exec(text)) !== null) {
        keyPositions.push({
            key: match[1].toUpperCase(),
            start: match.index,
            end: match.index + match[0].length
        });
    }

    const flatEntries: { key: string, value: string }[] = [];
    keyPositions.forEach((pos, i) => {
        const valueEnd = (i < keyPositions.length - 1) ? keyPositions[i + 1].start : text.length;
        const val = text.substring(pos.end, valueEnd).trim();
        const cleanVal = val.replace(/;$/, ''); 

        flatEntries.push({
            key: pos.key,
            value: cleanVal
        });
    });

    let currentNucleus: any = null;
    let currentReport: ImportReport | null = null;
    let currentItem: any = null;
    let currentItemType: 'QUESTION' | 'FLASHCARD' | 'PAIR' | null = null;
    let gapDataMap: Record<string, Record<string, string>> = {};

    const flushItem = () => {
        if (currentItem && currentNucleus) {
            const litRef = currentNucleus.id;
            const type = currentItemType || 'UNKNOWN';
            let idx = 1;
            let stableId = '';

            if (type === 'QUESTION') {
                const qRef = currentItem.q_ref || `Q${contents.length + 1}`;
                stableId = idGen.generateQuestionKey(litRef, qRef);
                if (!currentItem.questionText && currentItem.q_text) currentItem.questionText = currentItem.q_text;
                currentReport!.counts.questions++;
            } else if (type === 'FLASHCARD') {
                const fcRef = currentItem.fc_ref || `FC${contents.length + 1}`;
                stableId = idGen.makeDeterministicId(litRef, 'FLASHCARD', fcRef);
                currentReport!.counts.flashcards++;
            } else if (type === 'PAIR') {
                const pairRef = currentItem.pair_ref || `PAIR${contents.length + 1}`;
                stableId = idGen.makeDeterministicId(litRef, 'PAIR', pairRef);
                currentReport!.counts.pairs++;
                if (!currentItem.tags) currentItem.tags = [];
                if (!currentItem.tags.includes('pair-match')) currentItem.tags.push('pair-match');
            }

            if (!currentItem.lawRef) currentItem.lawRef = litRef;

            contents.push({
                id: stableId, // UPSERT KEY
                litRef, type, idx,
                payload: { ...currentItem, id: stableId } // Inject ID into payload
            });
            currentItem = null;
            currentItemType = null;
        }
    };

    const processGaps = () => {
        if (!currentNucleus || !currentReport) return;
        const GAP_REGEX = /{{\s*([^{}]+?)\s*}}/;

        Object.keys(gapDataMap).sort().forEach(xx => {
            const data = gapDataMap[xx];
            const rawText = data['LACUNA'] || '';
            const correctLetter = (data['CORRECT'] || '').trim().toUpperCase();

            // SANITIZE GAP OPTIONS TOO
            const options: Record<string, string> = {
                A: sanitizeOptionText(data['OPT_A']), 
                B: sanitizeOptionText(data['OPT_B']), 
                C: sanitizeOptionText(data['OPT_C']),
                D: sanitizeOptionText(data['OPT_D']), 
                E: sanitizeOptionText(data['OPT_E'])
            };

            const m = rawText.match(GAP_REGEX);
            let hasError = false;

            if (!m) { 
                const correctText = options[correctLetter];
                if (!correctText || !rawText.includes(correctText)) {
                     if (!options['A']) {
                        currentReport!.errors.push(`Lacuna ${xx}: Texto sem marcação {{ }} e sem opções.`);
                        hasError = true;
                     }
                }
            }

            if (!hasError) {
                const gapRef = `GAP-${xx}`;
                contents.push({
                    id: idGen.makeDeterministicId(currentNucleus.id, 'LACUNA', gapRef),
                    litRef: currentNucleus.id,
                    type: 'LACUNA',
                    idx: parseInt(xx),
                    payload: {
                        lacuna_text: rawText,
                        blank_text: rawText.replace(GAP_REGEX, '__________'),
                        correct_letter: correctLetter || 'A',
                        correct_text: options[correctLetter] || '',
                        options
                    }
                });
                currentReport!.counts.lacunas++;
            }
        });
        gapDataMap = {};
    };

    flatEntries.forEach(entry => {
        const { key, value } = entry;

        if (key === 'LIT_REF' || key === 'ARTICLE') {
            flushItem(); processGaps();

            // If LIT_REF is provided, use it. If not, we will construct later when we have LAW_ID + ARTICLE
            // But here we are iterating, so we might need to store temp state.
            // Simplified: The logic assumes LIT_REF starts the block.
            // If the user starts with ARTICLE and LAW_ID, we can construct the key.

            // For now, assume LIT_REF is the start or primary key. 
            // If key is ARTICLE, check if we already have a nucleus.

            if (key === 'LIT_REF') {
                const id = srs.canonicalizeLitRef(value);
                currentNucleus = { id, litRefProvided: true, importBatchId: batchId };
            } else if (key === 'ARTICLE') {
                if (!currentNucleus) {
                    currentNucleus = { article: value, importBatchId: batchId };
                } else {
                    currentNucleus.article = value;
                }
            }

            if (!currentNucleus.reportCreated) {
                currentReport = {
                    litRef: '',
                    status: 'SUCCESS', errors: [], warnings: [],
                    counts: { lacunas: 0, questions: 0, flashcards: 0, pairs: 0 },
                    detectedGaps: []
                };
                reports.push(currentReport);
                currentNucleus.reportCreated = true;
                nuclei.push(currentNucleus);
            }
        }
        else if (key === 'LAW_ID') {
            if (currentNucleus) currentNucleus.law_id = value;
        }
        else if (key.startsWith('PHASE2_')) {
            const m = key.match(/^PHASE2_(LACUNA|CORRECT|OPT_[A-E])_(\d+)$/);
            if (m) {
                const subKey = m[1];
                const xx = m[2];
                if (!gapDataMap[xx]) gapDataMap[xx] = {};
                gapDataMap[xx][subKey] = value;
            }
        } 
        else if (key === 'Q_REF') {
            flushItem(); 
            currentItemType = 'QUESTION'; 
            currentItem = { q_ref: value, options: {}, questionText: '' };
        } 
        else if (key === 'FC_REF') {
            flushItem(); 
            currentItemType = 'FLASHCARD'; 
            currentItem = { fc_ref: value, tags: [] };
        } 
        else if (key === 'PAIR_REF') {
            flushItem(); 
            currentItemType = 'PAIR'; 
            currentItem = { pair_ref: value, tags: ['pair-match'] };
        } 
        else if (currentItem) {
            if (['A','B','C','D','E'].includes(key) && currentItemType === 'QUESTION') {
                // APPLY SANITIZATION LAYER 1
                currentItem.options[key] = sanitizeOptionText(value);
            } 
            else if (key === 'Q_TEXT' || key === 'QUESTION_TEXT') {
                if (currentItemType === 'QUESTION') currentItem.questionText = value;
            }
            else if (key === 'CORRECT' || key === 'ANSWER') {
                currentItem.correctAnswer = value;
            }
            else if (key === 'FRONT') currentItem.front = value;
            else if (key === 'BACK') currentItem.back = value;
            else if (key === 'TOPIC_TITLE') currentItem.topic = value; // Para Pares
            else if (key === 'TAGS') {
                currentItem.tags = value.split(/[;,]/).map(t => t.trim()).filter(Boolean);
            }
            else if (key === 'LAW_REF') currentItem.lawRef = srs.canonicalizeLitRef(value);

            // Map common aliases for feedback fields
            else if (['COMENTARIO', 'EXPLAIN'].includes(key)) currentItem.explanation = value;
            else if (['PALAVRA_QUE_SALVA', 'KEY_DISTINCTION'].includes(key)) currentItem.key_distinction = value;
            else if (['FRASE_ANCORA_FINAL', 'ANCHOR_TEXT', 'FRASE_ANCORA'].includes(key)) currentItem.anchor_text = value;
            else if (['GUIA_TRAPSCAN', 'TRAPSCAN'].includes(key)) currentItem.guia_trapscan = value;
            else if (['EXPLANATION_TECH', 'EXPLICA_TECNICA'].includes(key)) currentItem.explanation_tech = value;
            else if (['EXPLANATION_STORY', 'HISTORIA', 'STORYTELLING'].includes(key)) currentItem.explanation_story = value;
            else if (['WRONG_DIAGNOSIS', 'DIAGNOSTICO_ERRO'].includes(key)) currentItem.wrong_diagnosis = value;
            else if (['DISTRACTOR_PROFILE', 'PERFIL_DISTRATORES'].includes(key)) currentItem.distractor_profile = value;
            else if (['WRONG_DIAGNOSIS_MAP', 'MAPA_ERRO'].includes(key)) currentItem.wrong_diagnosis_map = value;

            else {
                currentItem[key.toLowerCase()] = value;
            }
        } 
        else if (currentNucleus) {
            currentNucleus[key.toLowerCase()] = value;
        }
    });

    flushItem(); 
    processGaps();

    // FINAL ID STABILIZATION PASS
    nuclei.forEach((n, idx) => {
        // If ID is missing but we have Law and Article, generate DOC_KEY
        if (!n.id || !n.litRefProvided) {
             if (n.law_id && n.article) {
                 n.id = idGen.generateDocKey(n.law_id, n.article);
             } else {
                 // Fallback if malformed
                 n.id = `DOC_${idx}_${Date.now()}`;
             }
        }

        // Update reports with final ID
        if (reports[idx]) reports[idx].litRef = n.id;

        // Fix children linking
        contents.filter(c => c.litRef === '' || c.litRef === undefined || (reports[idx] && c.litRef === reports[idx].litRef)).forEach(c => {
             // If child doesn't have a litRef yet (from initial parse), assign parent
             c.litRef = n.id;

             // RE-GENERATE QUESTION ID with Parent ID to ensure Q_KEY stability
             if (c.type === 'QUESTION') {
                 const qRef = c.payload.questionRef || c.payload.q_ref || `Q${c.idx}`;
                 c.id = idGen.generateQuestionKey(n.id, qRef);
                 c.payload.id = c.id;
                 c.payload.lawRef = n.id;
             } else if (c.type === 'LACUNA') {
                 // Regenerate Gap ID to be safe
                 c.id = idGen.makeDeterministicId(n.id, 'LACUNA', c.idx);
             }
        });
    });

    return { batchId, nuclei, contents, reports };
};

export function parseLitRefText(text: string, settings: AppSettings, batchId: string, lawId?: string, forceLawId?: boolean): ImportResult {
    const { nuclei, contents, reports } = parseOfficialStrict(text, settings);
    const errors: string[] = [];
    reports.forEach(r => errors.push(...r.errors));

    const today = srs.todayISO();

    const gaps = contents.filter(c => c.type === 'LACUNA').map(c => ({
        id: c.id,
        litRef: c.litRef,
        type: 'LACUNA',
        payload: c.payload
    }));

    const cards: LiteralnessCard[] = nuclei.map(n => {
        const cardId = n.id;
        // Find gaps belonging to this card
        const cardGaps = gaps.filter(g => srs.canonicalizeLitRef(g.litRef) === srs.canonicalizeLitRef(cardId)).map(g => ({
             id: g.id,
             text: g.payload.lacuna_text || g.payload.text,
             correct: g.payload.correct_letter || g.payload.correct || 'A',
             options: g.payload.options || { A: 'Erro' },
             questionRef: `GAP-${g.payload.idx || '?'}`
        }));

        const card: LiteralnessCard = {
            id: cardId,
            lawId: forceLawId && lawId ? lawId : (n.law_id || lawId || 'Geral'),
            article: n.article || n.id,
            topic: n.topic || 'Geral',
            phase1Full: n.phase1_full || '',
            partsSummary: n.parts_summary || n.resumo_por_partes || '',
            keywordsProva: n.keywords_prova || '',
            riscoFcc: n.risco_fcc || '',
            gancho: n.gancho_mnemonico || '',
            storytelling: n.storytelling || '',
            feynmanExplanation: n.feynman || '',
            createdAt: today, nextReviewDate: today, lastReviewedAt: today, masteryScore: 0, totalAttempts: 0,
            stability: settings.srsV2.S_default_days,
            batteryProgress: 0, progressionLevel: 0, userNotes: '',
            contentType: 'LAW_DRY', importBatchId: batchId,
            extraGaps: cardGaps // POPULATE GAPS HERE
        };
        card.studyFlow = buildReadingSteps(card);
        return card;
    });

    const questions: Question[] = contents.filter(c => c.type === 'QUESTION').map(c => {
        const p = c.payload;

        // ENSURE OPTIONS ARE SANITIZED
        const rawOptions = p.options || { A: "Erro", B: "Erro" };
        const cleanOptions: any = {};
        Object.keys(rawOptions).forEach(k => {
             cleanOptions[k] = sanitizeOptionText(rawOptions[k]);
        });

        // Mapeamento dos campos do objeto temporário (lowercase) para o objeto Question (camelCase)
        return {
            id: c.id,
            questionRef: p.q_ref || `Q-${c.idx}`,
            questionText: p.questionText || p.q_text || 'Enunciado não encontrado',
            options: cleanOptions,
            correctAnswer: p.correctAnswer || 'A',

            // Core Explanation
            explanation: p.explanation || p.comentario || '',

            // Feedback Engine Mappings
            explanationTech: p.explanation_tech || p.explanation || '',
            explanationStory: p.explanation_story || p.storytelling,
            feynmanQuestions: p.perguntas_feynman || p.feynman,

            guiaTrapscan: p.guia_trapscan,
            keyDistinction: p.key_distinction || p.palavra_que_salva,
            anchorText: p.anchor_text || p.frase_ancora_final || p.frase_ancora,

            wrongDiagnosis: p.wrong_diagnosis || p.diagnostico_erro,
            // Critical Fix: Ensure maps are objects if they come as strings
            distractorProfile: typeof p.distractor_profile === 'string' ? parseMapString(p.distractor_profile) : p.distractor_profile, 
            wrongDiagnosisMap: typeof p.wrong_diagnosis_map === 'string' ? parseMapString(p.wrong_diagnosis_map) : p.wrong_diagnosis_map, 

            subject: p.discipline || cards.find(card => card.id === c.litRef)?.lawId || 'Geral',
            topic: p.topic || cards.find(card => card.id === c.litRef)?.article || 'Geral',
            lawRef: c.litRef,

            importBatchId: batchId,
            totalAttempts: 0, masteryScore: 0, attemptHistory: [],
            stability: settings.srsV2.S_default_days, nextReviewDate: today,
            createdAt: today, lastAttemptDate: '', errorCount: 0, timeSec: 0,
            selfEvalLevel: 0, willFallExam: false, srsStage: 0, correctStreak: 0,
            srsVersion: 2, sequenceNumber: 0, comments: '', questionType: 'Literalidade'
        } as unknown as Question;
    });

    const flashcards: Flashcard[] = contents.filter(c => c.type === 'FLASHCARD' || c.type === 'PAIR').map(c => {
        const p = c.payload;
        const tags = p.tags || [];
        if (c.type === 'PAIR' && !tags.includes('pair-match')) tags.push('pair-match');
        if (!tags.includes(c.litRef)) tags.push(c.litRef);

        return {
            id: c.id,
            front: p.front || 'Frente Vazia',
            back: p.back || 'Verso Vazio',
            discipline: p.discipline || cards.find(card => card.id === c.litRef)?.lawId || 'Geral',
            topic: p.topic || cards.find(card => card.id === c.litRef)?.article || 'Geral',
            tags: tags,
            type: 'basic',
            importBatchId: batchId, totalAttempts: 0, masteryScore: 0,
            stability: settings.srsV2.S_default_days, nextReviewDate: today,
            createdAt: today, updatedAt: today, lastAttemptDate: '',
            timeSec: 0, selfEvalLevel: 0, attemptHistory: [], masteryHistory: [],
            pairMatchPlayed: false, comments: ''
        } as unknown as Flashcard;
    });

    return {
        batchId, cards, questions, flashcards, gaps,
        stats: {
            cards: cards.length,
            questions: questions.length,
            flashcards: flashcards.filter(f => !f.tags.includes('pair-match')).length,
            pairs: flashcards.filter(f => f.tags.includes('pair-match')).length,
            gaps: gaps.length
        },
        errors
    };
}

export function enforceTargetLinkage(result: ImportResult, targetId: string): ImportResult {
    const canon = srs.canonicalizeLitRef(targetId);
    return {
        ...result,
        questions: (result.questions || []).map(q => ({ ...q, lawRef: canon })),
        flashcards: (result.flashcards || []).map(f => ({ ...f, tags: [...new Set([...(f.tags || []), canon])] })),
        // Also relink gaps if we were appending
        gaps: (result.gaps || []).map(g => ({ ...g, litRef: canon, id: idGen.makeDeterministicId(canon, 'LACUNA', g.payload.idx || 99) }))
    };
}

export function cleanBatchForExport(batch: any): any { return batch; }

export async function runImportSelfTest(): Promise<any> {
    const testText = `LIT_REF: TEST_01 LAW_ID: TEST ARTICLE: Art 1 PHASE1_FULL: Texto Q_REF: Q1 Q_TEXT: T? A: Sim; P7=Leaky B: Não CORRECT: A`;
    const mockSettings: any = { srsV2: { S_default_days: 1 } };
    const result = parseLitRefText(testText, mockSettings, 'TEST_BATCH');
    return { parseResult: result, auditReport: [] };
}

import * as storage from './storage';
import { LiteralnessCard, Question, Flashcard, SrsItem } from '../types';
import * as srs from './srsService';

/**
 * Repository Service
 * Centralizes all cross-store data access to ensure LIT_REF integrity.
 */

export const nucleusRepo = {
    /**
     * Rehydrates an article completely, fetching linked content directly from DB 
     * to avoid "missing items" UI bugs.
     */
    async getFullArticleData(litRef: string) {
        const canon = srs.canonicalizeLitRef(litRef);

        // 1. Get Core Card
        const cards = await storage.loadData<LiteralnessCard[]>('revApp_literalness_v1') || [];
        const card = cards.find(c => srs.canonicalizeLitRef(c.id) === canon);

        if (!card) return null;

        // 2. Direct Index Search in DB (Source of Truth)
        // Fix: storage.STORES.QUESTIONS/FLASHCARDS do not exist. Using STORES.CONTENT and filtering by type.
        const allItems = await storage.dbGetByIndex<any>(storage.STORES.CONTENT, 'litRef', canon);
        const questions = allItems.filter(i => i.type === 'QUESTION').map(i => i.payload as Question);
        const flashcards = allItems.filter(i => i.type === 'FLASHCARD' || i.type === 'PAIR').map(i => i.payload as Flashcard);

        return {
            card,
            questions: questions.filter(q => !q.isGapType),
            gaps: srs.getGapsForCard(card, questions),
            flashcards: flashcards.filter(f => !f.tags?.includes('pair-match')),
            pairs: flashcards.filter(f => f.tags?.includes('pair-match'))
        };
    },

    /**
     * Persists imported batch ensuring immutability rules.
     * IMPLEMENTS UPSERT AND CHILD REPLACEMENT STRATEGY.
     */
    async saveImportBatch(batch: { cards: LiteralnessCard[], questions: Question[], flashcards: Flashcard[] }) {
        // 1. Upsert Nucleus Cards
        // Since we are using put, it overwrites if ID exists.
        // We assume IDs are Canonical DOC_KEYs now.
        await storage.dbPut(storage.STORES.NUCLEUS, batch.cards);

        // 2. Handle Content Synchronization (Replace Children)
        // For each card in the batch, we must ensure the DB state matches the batch state for its children.
        // Any child in DB that is NOT in the batch must be deleted (Pruning).

        const contentStoreName = storage.STORES.CONTENT;
        const db = await storage.openDB();

        for (const card of batch.cards) {
            const litRef = card.id;

            // A. Get existing children from DB for this Card
            const existingItems = await storage.dbGetByIndex<any>(contentStoreName, 'litRef', litRef);

            // B. Get new children from Batch for this Card
            const newQuestions = batch.questions.filter(q => srs.canonicalizeLitRef(q.lawRef) === litRef);
            const newFlashcards = batch.flashcards.filter(fc => srs.isLinked(fc, litRef));

            const newIds = new Set<string>();
            const contentPayloads: any[] = [];

            // Prepare new payloads
            newQuestions.forEach(q => {
                 newIds.add(q.id);
                 contentPayloads.push({
                    id: q.id,
                    litRef: litRef,
                    type: 'QUESTION',
                    payload: q
                 });
            });

            newFlashcards.forEach(fc => {
                newIds.add(fc.id);
                contentPayloads.push({
                    id: fc.id,
                    litRef: litRef,
                    type: fc.tags?.includes('pair-match') ? 'PAIR' : 'FLASHCARD',
                    payload: fc
                });
            });

            // C. Identify Orphans (Exist in DB but not in New Batch)
            const orphans = existingItems.filter(item => !newIds.has(item.id));

            // D. Delete Orphans
            if (orphans.length > 0) {
                console.log(`[Repository] Pruning ${orphans.length} orphans for ${litRef}`);
                const tx = db.transaction(contentStoreName, 'readwrite');
                const store = tx.objectStore(contentStoreName);
                orphans.forEach(o => store.delete(o.id));
                await new Promise(resolve => tx.oncomplete = resolve);
            }

            // E. Upsert New Content
            if (contentPayloads.length > 0) {
                 await storage.dbPut(contentStoreName, contentPayloads);
            }
        }

        // Sync with legacy stores for context compatibility (keeping this for now as per original code)
        // (In a full migration, we'd remove the legacy loadData calls)
        const existingCards = await storage.loadData<LiteralnessCard[]>('revApp_literalness_v1') || [];
        const existingQs = await storage.loadData<Question[]>('revApp_questions_v5_react') || [];
        const existingFs = await storage.loadData<Flashcard[]>('revApp_flashcards_v1') || [];

        // For Legacy Stores, we also need to apply the upsert/replace logic partially
        // Filter out old versions of the cards we are importing
        const batchCardIds = new Set(batch.cards.map(c => c.id));
        const batchQuestionIds = new Set(batch.questions.map(q => q.id));
        const batchFlashcardIds = new Set(batch.flashcards.map(f => f.id));

        const updatedCards = [...existingCards.filter(ec => !batchCardIds.has(ec.id)), ...batch.cards];
        const updatedQs = [...existingQs.filter(eq => !batchQuestionIds.has(eq.id)), ...batch.questions];
        const updatedFs = [...existingFs.filter(ef => !batchFlashcardIds.has(ef.id)), ...batch.flashcards];

        await storage.saveData('revApp_literalness_v1', updatedCards);
        await storage.saveData('revApp_questions_v5_react', updatedQs);
        await storage.saveData('revApp_flashcards_v1', updatedFs);
    }
};

import * as srs from './srsService';

/**
 * Normalizes a Law Code/ID.
 */
export function normalizeLawCode(code: string): string {
    if (!code) return 'GERAL';
    return code.trim().toUpperCase()
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
        .replace(/[^A-Z0-9_]/g, "_")
        .replace(/_+/g, "_");
}

/**
 * CANONICAL DOC_KEY GENERATOR
 * Format: LAW_ID::LIT_REF
 * This ensures that if we re-import the same article, we generate the exact same ID.
 */
export function generateDocKey(lawId: string, litRef: string): string {
    const code = normalizeLawCode(lawId);
    const ref = srs.canonicalizeLitRef(litRef);
    return `${code}::${ref}`;
}

/**
 * CANONICAL QUESTION KEY GENERATOR
 * Format: Q_REF (Normalized)
 * Questions are unique by their Reference Code within the system.
 */
export function generateQuestionKey(qRef: string): string {
    return srs.canonicalizeLitRef(qRef);
}

/**
 * ID DETERMINÍSTICO (Legacy wrapper or Fallback)
 * Formato: LIT_REF::TYPE::IDX
 */
export function makeDeterministicId(litRef: string, type: string, idx: number | string): string {
    const canon = srs.canonicalizeLitRef(litRef);
    const idxStr = String(idx).padStart(2, '0');
    return `${canon}::${type.toUpperCase()}::${idxStr}`;
}

/**
 * ID ESTÁVEL (Alias para Determinístico)
 */
export function makeStableId(litRef: string, type: string, idx: number | string): string {
    return makeDeterministicId(litRef, type, idx);
}

export function makeProgressPk(userId: string, itemId: string): string {
    return `${userId}:${itemId}`;
}

import { LiteralnessCard, Question, Flashcard, AppSettings } from '../../types';
import * as srs from '../srsService';
import * as idGen from '../idGenerator';
import { buildReadingSteps } from '../readingParser';
import { sanitizeOptionText } from '../questionParser';

export interface ImportResult {
    batchId: string;
    cards: LiteralnessCard[];
    questions: Question[];
    flashcards: Flashcard[];
    gaps: any[]; 
    stats: {
        cards: number;
        questions: number;
        flashcards: number;
        pairs: number;
        gaps: number;
    };
    errors: string[];
}

export interface ImportReport {
    litRef: string;
    status: 'SUCCESS' | 'FAILED';
    errors: string[];
    warnings: string[];
    counts: {
        lacunas: number;
        questions: number;
        flashcards: number;
        pairs: number;
        gaps: number;
    };
    detectedGaps: string[];
}

/**
 * Helper: Parses a raw block of text into a dictionary of keys/values.
 * Handles multiline values.
 */
const parseBlock = (blockText: string): Record<string, string> => {
    const lines = blockText.split('\n');
    const result: Record<string, string> = {};
    let currentKey: string | null = null;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed || trimmed.startsWith('#')) continue;

        // Match "KEY: Value" or "OPT_A: Value"
        // We look for keys at the START of the line to avoid false positives inside text.
        // Valid keys: Uppercase letters, numbers, underscores.
        const match = trimmed.match(/^([A-Z0-9_]+)\s*[:=]\s*(.*)$/);

        if (match) {
            const key = match[1].toUpperCase();
            const value = match[2];
            result[key] = value;
            currentKey = key;
        } else if (currentKey) {
            // Append to previous key (multiline support)
            result[currentKey] += '\n' + trimmed;
        }
    }
    return result;
};

/**
 * MIIAULA ROBUST BLOCK PARSER
 * 1. Splits text into logical blocks (Card, Question, Flashcard).
 * 2. Parses each block independently to avoid context leaks.
 * 3. Enforces OPT_A...E structure.
 */
export const parseOfficialStrict = (text: string, settings: AppSettings): { 
    batchId: string, 
    nuclei: any[], 
    contents: any[],
    reports: ImportReport[] 
} => {
    const batchId = `BATCH_${Date.now()}`;
    const nuclei: any[] = [];
    const contents: any[] = [];
    const reports: ImportReport[] = [];
    const errors: string[] = [];

    // 1. Split into Blocks based on primary keys
    // We split by lines that START with specific headers to define block boundaries
    const rawBlocks = text.split(/(?=^(?:LIT_REF|Q_REF|FC_REF|PAIR_REF):)/m).filter(b => b.trim().length > 0);

    let currentCardId: string | null = null;
    let currentLawId: string = 'GERAL';
    let currentTopic: string = 'Geral';

    // Helper to create report if not exists
    const getOrCreateReport = (ref: string) => {
        let rep = reports.find(r => r.litRef === ref);
        if (!rep) {
            rep = {
                litRef: ref,
                status: 'SUCCESS',
                errors: [],
                warnings: [],
                counts: { lacunas: 0, questions: 0, flashcards: 0, pairs: 0 },
                detectedGaps: []
            };
            reports.push(rep);
        }
        return rep;
    };

    for (const block of rawBlocks) {
        const fields = parseBlock(block);

        // --- TYPE: LITERALNESS CARD (ARTICLE) ---
        if (fields.LIT_REF) {
            const litRef = srs.canonicalizeLitRef(fields.LIT_REF);
            const lawId = fields.LAW_ID || currentLawId;

            currentCardId = idGen.generateDocKey(lawId, litRef);
            currentLawId = lawId;
            currentTopic = fields.TOPIC || currentTopic;

            nuclei.push({
                ...fields,
                id: currentCardId,
                lawId: currentLawId, // Normalized in object creation later
                article: fields.ARTICLE || litRef,
                importBatchId: batchId
            });

            getOrCreateReport(currentCardId);
        }

        // --- TYPE: QUESTION ---
        else if (fields.Q_REF) {
            if (!currentCardId) {
                errors.push(`Questão ${fields.Q_REF} ignorada: Nenhum LIT_REF definido antes dela.`);
                continue;
            }

            const qRef = fields.Q_REF;
            const report = getOrCreateReport(currentCardId);

            // 1. Normalize Options (The Golden Rule)
            // Priority: OPT_A > A
            const opts: Record<string, string> = {};
            const keys = ['A', 'B', 'C', 'D', 'E'];

            keys.forEach(k => {
                let val = fields[`OPT_${k}`] || fields[k];
                if (val) opts[k] = sanitizeOptionText(val);
            });

            // 2. Normalize Correct Answer
            let correct = (fields.CORRECT || fields.ANSWER || '').trim().toUpperCase().charAt(0);

            // 3. Validation
            const isCebraspe = (fields.TYPE || '').includes('C/E') || (fields.BANK || '').toUpperCase().includes('CEBRASPE');
            let isValid = true;

            if (!fields.Q_TEXT) {
                report.errors.push(`${qRef}: Enunciado (Q_TEXT) vazio.`);
                isValid = false;
            }

            if (!correct) {
                 report.errors.push(`${qRef}: Gabarito (CORRECT) não definido.`);
                 isValid = false;
            }

            if (isCebraspe) {
                // Auto-fill C/E options if missing
                if (!opts.A) opts.A = 'Certo';
                if (!opts.B) opts.B = 'Errado';
                // Ensure C-E are empty
                opts.C = ''; opts.D = ''; opts.E = '';
            } else {
                // FCC / Standard: Require A-E
                const missingOpts = keys.filter(k => !opts[k]);
                if (missingOpts.length > 0) {
                    // Allow 4 options if standard for bank, but warn if < 4
                    if (missingOpts.length > 1) { // Tolerate missing E only
                        report.errors.push(`${qRef}: Alternativas faltando (${missingOpts.join(',')}).`);
                        isValid = false;
                    }
                }

                // Validate Correct points to existing option
                if (correct && !opts[correct]) {
                    report.errors.push(`${qRef}: Gabarito '${correct}' aponta para opção vazia.`);
                    isValid = false;
                }
            }

            if (isValid) {
                const qId = idGen.generateQuestionKey(qRef); // Stable ID based on Q_REF
                contents.push({
                    id: qId,
                    litRef: currentCardId,
                    type: 'QUESTION',
                    payload: {
                        ...fields,
                        id: qId,
                        questionRef: qRef,
                        questionText: fields.Q_TEXT,
                        options: opts, // Guaranteed clean object { A:..., B:... }
                        correctAnswer: correct,
                        lawRef: currentCardId,
                        // Clean legacy fields that might leak into logic
                        A: undefined, B: undefined, C: undefined, D: undefined, E: undefined,
                        OPT_A: undefined, OPT_B: undefined, OPT_C: undefined, OPT_D: undefined, OPT_E: undefined
                    }
                });
                report.counts.questions++;
            } else {
                report.status = 'FAILED';
            }
        }

        // --- TYPE: FLASHCARD / PAIR ---
        else if (fields.FC_REF || fields.PAIR_REF) {
            if (!currentCardId) continue;

            const ref = fields.FC_REF || fields.PAIR_REF;
            const type = fields.PAIR_REF ? 'PAIR' : 'FLASHCARD';
            const report = getOrCreateReport(currentCardId);

            contents.push({
                id: idGen.makeDeterministicId(currentCardId, type, ref),
                litRef: currentCardId,
                type: type,
                payload: {
                    ...fields,
                    id: ref,
                    fc_ref: ref,
                    pair_ref: ref,
                    front: fields.FRONT,
                    back: fields.BACK,
                    lawRef: currentCardId
                }
            });

            if (type === 'PAIR') report.counts.pairs++;
            else report.counts.flashcards++;
        }

        // --- TYPE: GAPS (PHASE2_LACUNA...) ---
        // Note: The original parser handled GAPS inside the Nucleus block loop or via regex.
        // For block parsing, GAPS might be separate or embedded in LIT_REF block. 
        // The `parseBlock` helper captures keys like PHASE2_LACUNA_01.
        // We need to extract them from the LIT_REF block payload in the `nuclei` processing step, 
        // or process them here if they appear as separate blocks (unlikely in current format).
        // Since `nuclei` items contain all fields from the block, we can process gaps post-hoc from the nuclei array.
    }

    // Process Gaps from Nuclei Fields
    nuclei.forEach(n => {
        const report = getOrCreateReport(n.id);
        const gapKeys = Object.keys(n).filter(k => k.startsWith('PHASE2_LACUNA_'));

        gapKeys.forEach(k => {
            const suffix = k.replace('PHASE2_LACUNA_', ''); // e.g. "01"
            const text = n[k];

            // Extract options and correct from flat fields
            const opts = {
                A: sanitizeOptionText(n[`PHASE2_OPT_A_${suffix}`]),
                B: sanitizeOptionText(n[`PHASE2_OPT_B_${suffix}`]),
                C: sanitizeOptionText(n[`PHASE2_OPT_C_${suffix}`]),
                D: sanitizeOptionText(n[`PHASE2_OPT_D_${suffix}`]),
                E: sanitizeOptionText(n[`PHASE2_OPT_E_${suffix}`]),
            };
            const correct = (n[`PHASE2_CORRECT_${suffix}`] || 'A').trim().toUpperCase();

            if (text) {
                const gapId = idGen.makeDeterministicId(n.id, 'LACUNA', suffix);
                contents.push({
                    id: gapId,
                    litRef: n.id,
                    type: 'LACUNA',
                    idx: parseInt(suffix) || 0,
                    payload: {
                        lacuna_text: text,
                        correct_letter: correct,
                        options: opts,
                        // Helper for blank text
                        blank_text: text.replace(/{{\s*.*?\s*}}/, '__________')
                    }
                });
                report.counts.lacunas++;
            }
        });
    });

    // Pass any global errors to the first report or a general bucket
    if (errors.length > 0 && reports.length > 0) {
        reports[0].errors.push(...errors);
    }

    return { batchId, nuclei, contents, reports };
};

export function parseLitRefText(text: string, settings: AppSettings, batchId: string, lawId?: string, forceLawId?: boolean): ImportResult {
    const { nuclei, contents, reports } = parseOfficialStrict(text, settings);
    const errors: string[] = [];
    reports.forEach(r => errors.push(...r.errors));

    const today = srs.todayISO();

    const gaps = contents.filter(c => c.type === 'LACUNA').map(c => ({
        id: c.id,
        litRef: c.litRef,
        type: 'LACUNA',
        payload: c.payload
    }));

    const cards: LiteralnessCard[] = nuclei.map(n => {
        const cardId = n.id;
        // Find gaps belonging to this card
        const cardGaps = gaps.filter(g => srs.canonicalizeLitRef(g.litRef) === srs.canonicalizeLitRef(cardId)).map(g => ({
             id: g.id,
             text: g.payload.lacuna_text || g.payload.text,
             correct: g.payload.correct_letter || g.payload.correct || 'A',
             options: g.payload.options || { A: 'Erro' },
             questionRef: `GAP-${g.payload.idx || '?'}`
        }));

        const card: LiteralnessCard = {
            id: cardId,
            lawId: forceLawId && lawId ? lawId : (n.lawId || lawId || 'Geral'), // Use n.lawId derived in parser
            article: n.ARTICLE || n.article || 'Artigo',
            topic: n.TOPIC || 'Geral',
            phase1Full: n.PHASE1_FULL || '',
            partsSummary: n.PARTS_SUMMARY || n.RESUMO_POR_PARTES || '',
            keywordsProva: n.KEYWORDS_PROVA || '',
            riscoFcc: n.RISCO_FCC || '',
            gancho: n.GANCHO_MNEMONICO || '',
            storytelling: n.STORYTELLING || '',
            feynmanExplanation: n.FEYNMAN || '',
            createdAt: today, nextReviewDate: today, lastReviewedAt: today, masteryScore: 0, totalAttempts: 0,
            stability: settings.srsV2.S_default_days,
            batteryProgress: 0, progressionLevel: 0, userNotes: '',
            contentType: 'LAW_DRY', importBatchId: batchId,
            extraGaps: cardGaps 
        };
        card.studyFlow = buildReadingSteps(card);
        return card;
    });

    const questions: Question[] = contents.filter(c => c.type === 'QUESTION').map(c => {
        const p = c.payload;

        return {
            id: c.id,
            questionRef: p.questionRef,
            questionText: p.questionText,
            options: p.options, // Already sanitized in parser
            correctAnswer: p.correctAnswer,

            explanation: p.EXPLANATION || '',
            explanationTech: p.EXPLANATION_TECH || '',
            explanationStory: p.EXPLANATION_STORY || '',
            feynmanQuestions: p.PERGUNTAS_FEYNMAN || '',

            guiaTrapscan: p.GUIA_TRAPSCAN || '',
            keyDistinction: p.KEY_DISTINCTION || '',
            anchorText: p.ANCHOR_TEXT || '',

            wrongDiagnosis: p.WRONG_DIAGNOSIS || '',
            // Map strings to objects if needed (Parser already did basic map for options, these might be strings)
            distractorProfile: parseMapString(p.DISTRACTOR_PROFILE), 
            wrongDiagnosisMap: parseMapString(p.WRONG_DIAGNOSIS_MAP),

            subject: p.DISCIPLINE || cards.find(card => card.id === c.litRef)?.lawId || 'Geral',
            topic: p.TOPIC || cards.find(card => card.id === c.litRef)?.article || 'Geral',
            lawRef: c.litRef,

            importBatchId: batchId,
            totalAttempts: 0, masteryScore: 0, attemptHistory: [],
            stability: settings.srsV2.S_default_days, nextReviewDate: today,
            createdAt: today, lastAttemptDate: '', errorCount: 0, timeSec: 0,
            selfEvalLevel: 0, willFallExam: false, srsStage: 0, correctStreak: 0,
            srsVersion: 2, sequenceNumber: 0, comments: '', 
            questionType: p.TYPE || 'Literalidade',

            hotTopic: !!p.HOT,
            isCritical: !!p.CRIT,
            isFundamental: !!p.FUND
        } as unknown as Question;
    });

    const flashcards: Flashcard[] = contents.filter(c => c.type === 'FLASHCARD' || c.type === 'PAIR').map(c => {
        const p = c.payload;
        const tags = p.TAGS ? p.TAGS.split(',').map((t:string)=>t.trim()) : [];
        if (c.type === 'PAIR' && !tags.includes('pair-match')) tags.push('pair-match');
        if (!tags.includes(c.litRef)) tags.push(c.litRef);

        return {
            id: c.id,
            front: p.FRONT || 'Frente Vazia',
            back: p.BACK || 'Verso Vazio',
            discipline: p.DISCIPLINE || cards.find(card => card.id === c.litRef)?.lawId || 'Geral',
            topic: p.TOPIC_TITLE || cards.find(card => card.id === c.litRef)?.article || 'Geral',
            tags: tags,
            type: 'basic',
            importBatchId: batchId, totalAttempts: 0, masteryScore: 0,
            stability: settings.srsV2.S_default_days, nextReviewDate: today,
            createdAt: today, updatedAt: today, lastAttemptDate: '',
            timeSec: 0, selfEvalLevel: 0, attemptHistory: [], masteryHistory: [],
            pairMatchPlayed: false, comments: ''
        } as unknown as Flashcard;
    });

    return {
        batchId, cards, questions, flashcards, gaps,
        stats: {
            cards: cards.length,
            questions: questions.length,
            flashcards: flashcards.filter(f => !f.tags.includes('pair-match')).length,
            pairs: flashcards.filter(f => f.tags.includes('pair-match')).length,
            gaps: gaps.length
        },
        errors
    };
}

export function enforceTargetLinkage(result: ImportResult, targetId: string): ImportResult {
    const canon = srs.canonicalizeLitRef(targetId);
    return {
        ...result,
        questions: (result.questions || []).map(q => ({ ...q, lawRef: canon })),
        flashcards: (result.flashcards || []).map(f => ({ ...f, tags: [...new Set([...(f.tags || []), canon])] })),
        // Also relink gaps if we were appending
        gaps: (result.gaps || []).map(g => ({ ...g, litRef: canon, id: idGen.makeDeterministicId(canon, 'LACUNA', g.payload.idx || 99) }))
    };
}

export function cleanBatchForExport(batch: any): any { return batch; }

export async function runImportSelfTest(): Promise<any> {
    const testText = `LIT_REF: TEST_01\nLAW_ID: TEST\nARTICLE: Art 1\nPHASE1_FULL: Texto\n\nQ_REF: Q1\nQ_TEXT: T?\nOPT_A: Sim\nOPT_B: Não\nCORRECT: A`;
    const mockSettings: any = { srsV2: { S_default_days: 1 } };
    const result = parseLitRefText(testText, mockSettings, 'TEST_BATCH');
    return { parseResult: result, auditReport: [] };
}

import * as storage from './storage';
import { LiteralnessCard, Question, Flashcard, SrsItem } from '../types';
import * as srs from './srsService';

/**
 * Repository Service
 * Centralizes all cross-store data access to ensure LIT_REF integrity.
 */

export const nucleusRepo = {
    /**
     * Rehydrates an article completely, fetching linked content directly from DB 
     * to avoid "missing items" UI bugs.
     */
    async getFullArticleData(litRef: string) {
        const canon = srs.canonicalizeLitRef(litRef);

        // 1. Get Core Card
        const cards = await storage.loadData<LiteralnessCard[]>('revApp_literalness_v1') || [];
        const card = cards.find(c => srs.canonicalizeLitRef(c.id) === canon);

        if (!card) return null;

        // 2. Direct Index Search in DB (Source of Truth)
        // Fix: storage.STORES.QUESTIONS/FLASHCARDS do not exist. Using STORES.CONTENT and filtering by type.
        const allItems = await storage.dbGetByIndex<any>(storage.STORES.CONTENT, 'litRef', canon);
        const questions = allItems.filter(i => i.type === 'QUESTION').map(i => i.payload as Question);
        const flashcards = allItems.filter(i => i.type === 'FLASHCARD' || i.type === 'PAIR').map(i => i.payload as Flashcard);

        return {
            card,
            questions: questions.filter(q => !q.isGapType),
            gaps: srs.getGapsForCard(card, questions),
            flashcards: flashcards.filter(f => !f.tags?.includes('pair-match')),
            pairs: flashcards.filter(f => f.tags?.includes('pair-match'))
        };
    },

    /**
     * Persists imported batch ensuring immutability rules.
     * IMPLEMENTS UPSERT AND CHILD REPLACEMENT STRATEGY.
     */
    async saveImportBatch(batch: { cards: LiteralnessCard[], questions: Question[], flashcards: Flashcard[] }) {
        // 1. Upsert Nucleus Cards
        // Since we are using put, it overwrites if ID exists (Upsert).
        await storage.dbPut(storage.STORES.NUCLEUS, batch.cards);

        // 2. Handle Content Synchronization (Replace Children)
        // For each card in the batch, we must ensure the DB state matches the batch state for its children.
        // Any child in DB that is NOT in the batch must be deleted (Pruning).

        const contentStoreName = storage.STORES.CONTENT;
        const db = await storage.openDB();

        for (const card of batch.cards) {
            const litRef = card.id;

            // A. Get existing children from DB for this Card
            // This is crucial: we fetch what is currently stored for this LitRef
            const existingItems = await storage.dbGetByIndex<any>(contentStoreName, 'litRef', litRef);

            // B. Get new children from Batch for this Card
            // We use canonical LitRef to match
            const newQuestions = batch.questions.filter(q => srs.canonicalizeLitRef(q.lawRef) === litRef);
            const newFlashcards = batch.flashcards.filter(fc => srs.isLinked(fc, litRef));

            const newIds = new Set<string>();
            const contentPayloads: any[] = [];

            // Prepare new payloads and collect IDs
            newQuestions.forEach(q => {
                 newIds.add(q.id);
                 contentPayloads.push({
                    id: q.id,
                    litRef: litRef,
                    type: 'QUESTION',
                    payload: q
                 });
            });

            newFlashcards.forEach(fc => {
                newIds.add(fc.id);
                contentPayloads.push({
                    id: fc.id,
                    litRef: litRef,
                    type: fc.tags?.includes('pair-match') ? 'PAIR' : 'FLASHCARD',
                    payload: fc
                });
            });

            // C. Identify Orphans (Exist in DB but not in New Batch)
            // If the batch updates the card, any question NOT in the batch should be considered "Deleted" or "Archived"
            const orphans = existingItems.filter(item => !newIds.has(item.id));

            // D. Delete Orphans
            if (orphans.length > 0) {
                console.log(`[Repository] Pruning ${orphans.length} orphans for ${litRef}`);
                const tx = db.transaction(contentStoreName, 'readwrite');
                const store = tx.objectStore(contentStoreName);
                orphans.forEach(o => store.delete(o.id));
                await new Promise(resolve => tx.oncomplete = resolve);
            }

            // E. Upsert New Content
            if (contentPayloads.length > 0) {
                 await storage.dbPut(contentStoreName, contentPayloads);
            }
        }

        // Sync with legacy stores for context compatibility (keeping this for now as per original code)
        // (In a full migration, we'd remove the legacy loadData calls)
        const existingCards = await storage.loadData<LiteralnessCard[]>('revApp_literalness_v1') || [];
        const existingQs = await storage.loadData<Question[]>('revApp_questions_v5_react') || [];
        const existingFs = await storage.loadData<Flashcard[]>('revApp_flashcards_v1') || [];

        // For Legacy Stores, we also need to apply the upsert/replace logic partially
        // Filter out old versions of the cards we are importing
        const batchCardIds = new Set(batch.cards.map(c => c.id));
        const batchQuestionIds = new Set(batch.questions.map(q => q.id));
        const batchFlashcardIds = new Set(batch.flashcards.map(f => f.id));

        const updatedCards = [...existingCards.filter(ec => !batchCardIds.has(ec.id)), ...batch.cards];
        const updatedQs = [...existingQs.filter(eq => !batchQuestionIds.has(eq.id)), ...batch.questions];
        const updatedFs = [...existingFs.filter(ef => !batchFlashcardIds.has(ef.id)), ...batch.flashcards];

        await storage.saveData('revApp_literalness_v1', updatedCards);
        await storage.saveData('revApp_questions_v5_react', updatedQs);
        await storage.saveData('revApp_flashcards_v1', updatedFs);
    }
};

import React, { useMemo } from 'react';
import { Question, EvidenceItem } from '../types';
import { CheckCircleIcon, XCircleIcon, LockClosedIcon, TrashIcon, ScaleIcon, ExclamationTriangleIcon } from './icons';
import QuestionExplanationBlocks from './QuestionExplanationBlocks';
import PromptText from './ui/PromptText';
import { getSafeQuestionView, sanitizeOptionText } from '../services/questionParser';

interface QuestionViewerProps {
    question: Question;
    selectedOption: string | null;
    isRevealed: boolean;
    onOptionSelect?: (key: string) => void;
    className?: string;
    showMedia?: boolean;
    isLocked?: boolean; 

    eliminatedOptions?: string[];
    onEliminate?: (key: string) => void;
    isEliminationMode?: boolean;
    highlightText?: string;

    evidence?: { stem: EvidenceItem[], options: Record<string, EvidenceItem[]> } | undefined;
    orderedKeys?: string[]; 
}

const QuestionViewer: React.FC<QuestionViewerProps> = ({ 
    question, 
    selectedOption, 
    isRevealed, 
    onOptionSelect, 
    className = "",
    showMedia = true,
    isLocked = false,
    eliminatedOptions = [],
    onEliminate,
    isEliminationMode = false,
    highlightText,
    evidence,
    orderedKeys
}) => {

    // --- SAFE VIEW LAYER ---
    // Create a safe, non-mutated view of the question where we try to recover 
    // any missing options from the raw block.
    const safeQuestion = useMemo(() => getSafeQuestionView(question), [question]);

    const handleOptionClick = (key: string) => {
        if (isLocked) return;

        if (isEliminationMode && onEliminate) {
            onEliminate(key);
            return;
        }

        if (eliminatedOptions.includes(key)) return;

        if (!isRevealed && onOptionSelect) {
            onOptionSelect(key);
        }
    };

    // Detect if this should be rendered as a Gap/Cloze question
    const isGapMode = useMemo(() => {
        if (safeQuestion.isGapType) return true;
        const text = safeQuestion.questionText || '';
        return /\{\{.+?\}\}|_{3,}/.test(text);
    }, [safeQuestion]);

    // Detect if this is a True/False (Certo/Errado) Judgement question
    const isJudgementMode = useMemo(() => {
        if (isGapMode) return false;
        const type = (safeQuestion.questionType || '').toUpperCase();
        const bank = (safeQuestion.bank || '').toUpperCase();

        // Explicit Type or Bank detection
        if (type.includes('C/E') || type.includes('CERTO') || type.includes('JULGAMENTO') || type.includes('V/F')) return true;
        if (bank.includes('CESPE') || bank.includes('CEBRASPE')) return true;

        // Content detection
        const optValues = Object.values(safeQuestion.options || {}).map(v => ((v as string) || '').trim().toUpperCase());
        if (optValues.includes('CERTO') && optValues.includes('ERRADO')) return true;

        return false;
    }, [safeQuestion, isGapMode]);

    // Resolve keys for Certo and Errado
    const judgementKeys = useMemo(() => {
        if (!isJudgementMode) return null;
        let rightKey = '';
        let wrongKey = '';

        Object.entries(safeQuestion.options || {}).forEach(([k, v]) => {
            const val = ((v as string) || '').toUpperCase().trim();
            if (val === 'CERTO') rightKey = k;
            if (val === 'ERRADO') wrongKey = k;
        });

        if (!rightKey || !wrongKey) {
            if (safeQuestion.options['C'] && !safeQuestion.options['A']) {
                rightKey = 'C'; wrongKey = 'E';
            } else {
                rightKey = 'A'; wrongKey = 'B';
            }
        }

        return { rightKey, wrongKey };
    }, [isJudgementMode, safeQuestion.options]);

    const renderQuestionText = () => {
        if (!isGapMode && highlightText && safeQuestion.questionText.includes(highlightText)) {
            const parts = safeQuestion.questionText.split(highlightText);
            return (
                <span>
                    {parts.map((part, i) => (
                        <React.Fragment key={i}>
                            <PromptText text={part} className="inline" />
                            {i < parts.length - 1 && (
                                <span className="bg-sky-500/30 text-white px-1 rounded animate-pulse font-bold border-b-2 border-sky-500">
                                    {highlightText}
                                </span>
                            )}
                        </React.Fragment>
                    ))}
                </span>
            );
        }

        return (
            <PromptText 
                text={safeQuestion.questionText} 
                mode={isGapMode ? 'gap' : 'plain'}
                revealExpected={isRevealed}
                highlights={evidence?.stem} 
            />
        );
    };

    // Calculate options from SAFE VIEW
    const optionsState = useMemo(() => {
        const ALL_KEYS = ['A', 'B', 'C', 'D', 'E'];

        return ALL_KEYS.map(key => {
            // Force access to specific key
            const raw = safeQuestion.options[key];
            const clean = sanitizeOptionText(raw as string);

            // Even if empty, we render it but mark disabled, unless it's null/undefined
            const isEmpty = !clean || clean.length === 0;
            const text = isEmpty ? "(Alternativa vazia)" : clean;

            return { 
                key, 
                text, 
                isDisabled: isEmpty 
            };
        });
    }, [safeQuestion.options]);

    // Check if the correct answer points to a disabled option
    const isCorrectAnswerInvalid = useMemo(() => {
        if (isJudgementMode) return false;
        const correctOpt = optionsState.find(o => o.key === safeQuestion.correctAnswer);
        return correctOpt ? correctOpt.isDisabled : true; 
    }, [optionsState, safeQuestion.correctAnswer, isJudgementMode]);

    return (
        <div className={`space-y-6 pb-10 ${className}`}>
            <div id="question-start-anchor" className="h-px w-full -mt-2"></div>

            {showMedia && (safeQuestion.questionImage || safeQuestion.questionAudio) && (
                <div className="flex flex-col gap-4 mb-4">
                    {safeQuestion.questionImage && <img src={safeQuestion.questionImage} alt="Questão" className="max-w-full rounded-lg max-h-80 object-contain mx-auto bg-black/20" />}
                    {safeQuestion.questionAudio && <audio controls src={safeQuestion.questionAudio} className="w-full" />}
                </div>
            )}

            {/* Warning Banner for Broken Data */}
            {isCorrectAnswerInvalid && !isJudgementMode && (
                <div className="bg-rose-500/10 border border-rose-500/20 p-3 rounded-lg flex items-center gap-3 animate-fade-in mb-4">
                    <ExclamationTriangleIcon className="w-5 h-5 text-rose-500" />
                    <p className="text-xs text-rose-200">
                        <strong>Atenção:</strong> O gabarito desta questão ({safeQuestion.correctAnswer}) aponta para uma alternativa vazia.
                    </p>
                </div>
            )}

            {/* Question Text */}
            <div className="text-base md:text-lg font-medium leading-relaxed text-slate-200">
                {renderQuestionText()}
            </div>

            <div className="relative">
                {/* LOCKED OVERLAY */}
                {isLocked && (
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-slate-900/10 backdrop-blur-sm rounded-xl border border-white/5 animate-fade-in">
                        <div className="bg-slate-900 p-4 rounded-full shadow-2xl border border-indigo-500/50 mb-3 animate-bounce-subtle">
                            <LockClosedIcon className="w-8 h-8 text-indigo-400" />
                        </div>
                        <p className="text-sm font-bold text-white bg-slate-900/80 px-4 py-2 rounded-lg shadow-lg border border-white/10">
                            Complete o P1 e P2 para liberar
                        </p>
                    </div>
                )}

                {/* ELIMINATION MODE INDICATOR */}
                {isEliminationMode && !isLocked && (
                    <div className="absolute -top-10 left-0 w-full flex justify-center pointer-events-none z-30">
                        <div className="bg-rose-500 text-white px-4 py-1 rounded-full text-xs font-black uppercase tracking-widest shadow-lg animate-pulse flex items-center gap-2">
                            <TrashIcon className="w-3 h-3" /> Modo Eliminação Ativo
                        </div>
                    </div>
                )}

                {/* SPECIAL UI FOR JUDGEMENT (CERTO/ERRADO) */}
                {isJudgementMode && judgementKeys ? (
                    <div className={`grid grid-cols-2 gap-4 mt-6 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`}>
                        {/* CERTO BUTTON */}
                        <button
                            onClick={() => handleOptionClick(judgementKeys.rightKey)}
                            disabled={isRevealed || isLocked}
                            className={`
                                relative p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-[0.98]
                                ${isRevealed
                                    ? (safeQuestion.correctAnswer === judgementKeys.rightKey 
                                        ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' 
                                        : (selectedOption === judgementKeys.rightKey ? 'bg-rose-500/20 border-rose-500 text-rose-400' : 'bg-white/5 border-white/5 text-slate-500 opacity-50'))
                                    : (selectedOption === judgementKeys.rightKey
                                        ? 'bg-sky-600 border-sky-500 text-white shadow-lg'
                                        : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-emerald-500/50 text-slate-300')
                                }
                            `}
                        >
                            <CheckCircleIcon className="w-8 h-8 mb-1" />
                            <span className="text-lg font-black uppercase tracking-widest">Certo</span>
                        </button>

                        {/* ERRADO BUTTON */}
                        <button
                            onClick={() => handleOptionClick(judgementKeys.wrongKey)}
                            disabled={isRevealed || isLocked}
                            className={`
                                relative p-6 rounded-2xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-[0.98]
                                ${isRevealed
                                    ? (safeQuestion.correctAnswer === judgementKeys.wrongKey 
                                        ? 'bg-emerald-500/20 border-emerald-500 text-emerald-400' 
                                        : (selectedOption === judgementKeys.wrongKey ? 'bg-rose-500/20 border-rose-500 text-rose-400' : 'bg-white/5 border-white/5 text-slate-500 opacity-50'))
                                    : (selectedOption === judgementKeys.wrongKey
                                        ? 'bg-sky-600 border-sky-500 text-white shadow-lg'
                                        : 'bg-white/5 border-white/10 hover:bg-white/10 hover:border-rose-500/50 text-slate-300')
                                }
                            `}
                        >
                            <XCircleIcon className="w-8 h-8 mb-1" />
                            <span className="text-lg font-black uppercase tracking-widest">Errado</span>
                        </button>

                        {/* Judgement Label */}
                        <div className="col-span-2 text-center mt-2">
                             <span className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em] flex items-center justify-center gap-2">
                                <ScaleIcon className="w-3 h-3" /> Julgue o Item
                             </span>
                        </div>
                    </div>
                ) : (
                    /* STANDARD MULTIPLE CHOICE UI */
                    <div className={`space-y-2 transition-all duration-500 ${isLocked ? 'opacity-30 filter blur-[3px] pointer-events-none' : 'opacity-100'}`} id="answers-block">
                        {optionsState.map(({ key, text, isDisabled }, index) => {
                            const isEliminated = eliminatedOptions.includes(key);
                            const isSelected = selectedOption === key;
                            const isCorrect = safeQuestion.correctAnswer === key;
                            const highlights = evidence?.options[key]; 

                            const visualLabel = key; // Keep A, B, C... as keys are already iterated

                            let btnClass = "w-full text-left p-3.5 rounded-xl border-2 transition-all flex gap-3 items-start group ";

                            // Style Logic
                            if (isDisabled) {
                                // Invalid Option State
                                btnClass += "bg-black/20 border-white/5 text-slate-600 cursor-not-allowed italic opacity-70";
                            } else if (isEliminated) {
                                btnClass += "bg-slate-900/50 border-transparent opacity-40 grayscale decoration-slate-500 line-through cursor-not-allowed";
                            } else if (isRevealed) {
                                if (isCorrect) {
                                    btnClass += "bg-emerald-500/20 border-emerald-500 text-emerald-100";
                                } else if (isSelected) {
                                    btnClass += "bg-rose-500/20 border-rose-500 text-rose-100";
                                } else {
                                    btnClass += "bg-white/5 border-white/5 opacity-50";
                                }
                            } else {
                                if (isEliminationMode) {
                                    btnClass += "bg-white/5 border-rose-500/30 hover:bg-rose-500/10 hover:border-rose-500 text-slate-300 cursor-crosshair";
                                } else if (isSelected) {
                                    btnClass += "bg-sky-600 border-sky-500 text-white shadow-lg";
                                } else {
                                    btnClass += "bg-white/5 border-white/10 hover:border-sky-500/30 hover:bg-white/10 active:scale-[0.99]";
                                }
                            }

                            return (
                                <button
                                    key={key}
                                    onClick={() => !isDisabled && handleOptionClick(key)}
                                    disabled={isDisabled || isRevealed || (isLocked)}
                                    className={btnClass}
                                    title={isDisabled ? "Opção inválida ou vazia no cadastro." : undefined}
                                >
                                    <strong className={`shrink-0 text-base ${!isDisabled && !isRevealed && !isSelected && !isEliminated ? 'text-sky-500 group-hover:text-sky-400' : 'text-current'}`}>{visualLabel})</strong>
                                    <span className="leading-snug pt-0.5 text-sm md:text-base w-full">
                                        <PromptText text={text} highlights={highlights} />
                                    </span>
                                    {isDisabled && <ExclamationTriangleIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                                    {isRevealed && isCorrect && <CheckCircleIcon className="w-5 h-5 ml-auto shrink-0 text-emerald-400" />}
                                    {isRevealed && isSelected && !isCorrect && <XCircleIcon className="w-5 h-5 ml-auto shrink-0 text-rose-400" />}
                                    {!isRevealed && isEliminated && <TrashIcon className="w-4 h-4 ml-auto shrink-0 text-slate-600" />}
                                </button>
                            );
                        })}
                    </div>
                )}
            </div>

            {isRevealed && (
                <div className="animate-fade-in pt-6 border-t border-white/10">
                   <QuestionExplanationBlocks 
                        question={safeQuestion} 
                        userAnswer={selectedOption} 
                        showTitle={true}
                   />
                </div>
            )}
        </div>
    );
};

export default QuestionViewer;

import { LiteralnessCard, Question, Flashcard, AppSettings } from '../../types';
import * as srs from '../srsService';
import * as idGen from '../idGenerator';
import { buildReadingSteps } from '../readingParser';
import { sanitizeOptionText } from '../questionParser';
import { parseDiagnosisMap } from '../../utils/feedbackFormatters';

export interface ImportResult {
    batchId: string;
    cards: LiteralnessCard[];
    questions: Question[];
    flashcards: Flashcard[];
    gaps: any[]; 
    stats: {
        cards: number;
        questions: number;
        flashcards: number;
        pairs: number;
        gaps: number;
    };
    errors: string[];
}

export interface ImportReport {
    litRef: string;
    status: 'SUCCESS' | 'FAILED';
    errors: string[];
    warnings: string[];
    counts: {
        lacunas: number;
        questions: number;
        flashcards: number;
        pairs: number;
        gaps: number;
    };
    detectedGaps: string[];
}

/**
 * Helper: Parses a raw block of text into a dictionary of keys/values.
 * Handles multiline values.
 */
const parseBlock = (blockText: string): Record<string, string> => {
    const lines = blockText.split('\n');
    const result: Record<string, string> = {};
    let currentKey: string | null = null;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed || trimmed.startsWith('#')) continue;

        // Match "KEY: Value" or "OPT_A: Value"
        // We look for keys at the START of the line to avoid false positives inside text.
        // Valid keys: Uppercase letters, numbers, underscores.
        const match = trimmed.match(/^([A-Z0-9_]+)\s*[:=]\s*(.*)$/);

        if (match) {
            const key = match[1].toUpperCase();
            const value = match[2];
            result[key] = value;
            currentKey = key;
        } else if (currentKey) {
            // Append to previous key (multiline support)
            result[currentKey] += '\n' + trimmed;
        }
    }
    return result;
};

/**
 * MIIAULA ROBUST BLOCK PARSER
 * 1. Splits text into logical blocks (Card, Question, Flashcard).
 * 2. Parses each block independently to avoid context leaks.
 * 3. Enforces OPT_A...E structure.
 */
export const parseOfficialStrict = (text: string, settings: AppSettings): { 
    batchId: string, 
    nuclei: any[], 
    contents: any[],
    reports: ImportReport[] 
} => {
    const batchId = `BATCH_${Date.now()}`;
    const nuclei: any[] = [];
    const contents: any[] = [];
    const reports: ImportReport[] = [];
    const errors: string[] = [];

    // 1. Split into Blocks based on primary keys
    // We split by lines that START with specific headers to define block boundaries
    const rawBlocks = text.split(/(?=^(?:LIT_REF|Q_REF|FC_REF|PAIR_REF):)/m).filter(b => b.trim().length > 0);

    let currentCardId: string | null = null;
    let currentLawId: string = 'GERAL';
    let currentTopic: string = 'Geral';

    // Helper to create report if not exists
    const getOrCreateReport = (ref: string) => {
        let rep = reports.find(r => r.litRef === ref);
        if (!rep) {
            rep = {
                litRef: ref,
                status: 'SUCCESS',
                errors: [],
                warnings: [],
                counts: { lacunas: 0, questions: 0, flashcards: 0, pairs: 0, gaps: 0 },
                detectedGaps: []
            };
            reports.push(rep);
        }
        return rep;
    };

    for (const block of rawBlocks) {
        const fields = parseBlock(block);

        // --- TYPE: LITERALNESS CARD (ARTICLE) ---
        if (fields.LIT_REF) {
            const litRef = srs.canonicalizeLitRef(fields.LIT_REF);
            const lawId = fields.LAW_ID || currentLawId;

            currentCardId = idGen.generateDocKey(lawId, litRef);
            currentLawId = lawId;
            currentTopic = fields.TOPIC || currentTopic;

            nuclei.push({
                ...fields,
                id: currentCardId,
                lawId: currentLawId, // Normalized in object creation later
                article: fields.ARTICLE || litRef,
                importBatchId: batchId
            });

            getOrCreateReport(currentCardId);
        }

        // --- TYPE: QUESTION ---
        else if (fields.Q_REF) {
            if (!currentCardId) {
                errors.push(`Questão ${fields.Q_REF} ignorada: Nenhum LIT_REF definido antes dela.`);
                continue;
            }

            const qRef = fields.Q_REF;
            const report = getOrCreateReport(currentCardId);

            // 1. Normalize Options (The Golden Rule)
            // Priority: OPT_A > A
            const opts: Record<string, string> = {};
            const keys = ['A', 'B', 'C', 'D', 'E'];

            keys.forEach(k => {
                let val = fields[`OPT_${k}`] || fields[k];
                if (val) opts[k] = sanitizeOptionText(val);
            });

            // 2. Normalize Correct Answer
            let correct = (fields.CORRECT || fields.ANSWER || '').trim().toUpperCase().charAt(0);

            // 3. Validation
            const isCebraspe = (fields.TYPE || '').includes('C/E') || (fields.BANK || '').toUpperCase().includes('CEBRASPE');
            let isValid = true;

            if (!fields.Q_TEXT) {
                report.errors.push(`${qRef}: Enunciado (Q_TEXT) vazio.`);
                isValid = false;
            }

            if (!correct) {
                 report.errors.push(`${qRef}: Gabarito (CORRECT) não definido.`);
                 isValid = false;
            }

            if (isCebraspe) {
                // Auto-fill C/E options if missing
                if (!opts.A) opts.A = 'Certo';
                if (!opts.B) opts.B = 'Errado';
                // Ensure C-E are empty
                opts.C = ''; opts.D = ''; opts.E = '';
            } else {
                // FCC / Standard: Require A-E
                const missingOpts = keys.filter(k => !opts[k]);
                if (missingOpts.length > 0) {
                    // Allow 4 options if standard for bank, but warn if < 4
                    if (missingOpts.length > 1) { // Tolerate missing E only
                        report.errors.push(`${qRef}: Alternativas faltando (${missingOpts.join(',')}).`);
                        isValid = false;
                    }
                }

                // Validate Correct points to existing option
                if (correct && !opts[correct]) {
                    report.errors.push(`${qRef}: Gabarito '${correct}' aponta para opção vazia.`);
                    isValid = false;
                }
            }

            if (isValid) {
                const qId = idGen.generateQuestionKey(qRef); // Stable ID based on Q_REF
                contents.push({
                    id: qId,
                    litRef: currentCardId,
                    type: 'QUESTION',
                    payload: {
                        ...fields,
                        id: qId,
                        questionRef: qRef,
                        questionText: fields.Q_TEXT,
                        options: opts, // Guaranteed clean object { A:..., B:... }
                        correctAnswer: correct,
                        lawRef: currentCardId,
                        // Clean legacy fields that might leak into logic
                        A: undefined, B: undefined, C: undefined, D: undefined, E: undefined,
                        OPT_A: undefined, OPT_B: undefined, OPT_C: undefined, OPT_D: undefined, OPT_E: undefined
                    }
                });
                report.counts.questions++;
            } else {
                report.status = 'FAILED';
            }
        }

        // --- TYPE: FLASHCARD / PAIR ---
        else if (fields.FC_REF || fields.PAIR_REF) {
            if (!currentCardId) continue;

            const ref = fields.FC_REF || fields.PAIR_REF;
            const type = fields.PAIR_REF ? 'PAIR' : 'FLASHCARD';
            const report = getOrCreateReport(currentCardId);

            contents.push({
                id: idGen.makeDeterministicId(currentCardId, type, ref),
                litRef: currentCardId,
                type: type,
                payload: {
                    ...fields,
                    id: ref,
                    fc_ref: ref,
                    pair_ref: ref,
                    front: fields.FRONT,
                    back: fields.BACK,
                    lawRef: currentCardId
                }
            });

            if (type === 'PAIR') report.counts.pairs++;
            else report.counts.flashcards++;
        }

        // --- TYPE: GAPS (PHASE2_LACUNA...) ---
        // Note: The original parser handled GAPS inside the Nucleus block loop or via regex.
        // For block parsing, GAPS might be separate or embedded in LIT_REF block. 
        // The `parseBlock` helper captures keys like PHASE2_LACUNA_01.
        // We need to extract them from the LIT_REF block payload in the `nuclei` processing step, 
        // or process them here if they appear as separate blocks (unlikely in current format).
        // Since `nuclei` items contain all fields from the block, we can process gaps post-hoc from the nuclei array.
    }

    // Process Gaps from Nuclei Fields
    nuclei.forEach(n => {
        const report = getOrCreateReport(n.id);
        const gapKeys = Object.keys(n).filter(k => k.startsWith('PHASE2_LACUNA_'));

        gapKeys.forEach(k => {
            const suffix = k.replace('PHASE2_LACUNA_', ''); // e.g. "01"
            const text = n[k];

            // Extract options and correct from flat fields
            const opts = {
                A: sanitizeOptionText(n[`PHASE2_OPT_A_${suffix}`]),
                B: sanitizeOptionText(n[`PHASE2_OPT_B_${suffix}`]),
                C: sanitizeOptionText(n[`PHASE2_OPT_C_${suffix}`]),
                D: sanitizeOptionText(n[`PHASE2_OPT_D_${suffix}`]),
                E: sanitizeOptionText(n[`PHASE2_OPT_E_${suffix}`]),
            };
            const correct = (n[`PHASE2_CORRECT_${suffix}`] || 'A').trim().toUpperCase();

            if (text) {
                const gapId = idGen.makeDeterministicId(n.id, 'LACUNA', suffix);
                contents.push({
                    id: gapId,
                    litRef: n.id,
                    type: 'LACUNA',
                    idx: parseInt(suffix) || 0,
                    payload: {
                        lacuna_text: text,
                        correct_letter: correct,
                        options: opts,
                        // Helper for blank text
                        blank_text: text.replace(/{{\s*.*?\s*}}/, '__________')
                    }
                });
                report.counts.lacunas++;
            }
        });
    });

    // Pass any global errors to the first report or a general bucket
    if (errors.length > 0 && reports.length > 0) {
        reports[0].errors.push(...errors);
    }

    return { batchId, nuclei, contents, reports };
};

export function parseLitRefText(text: string, settings: AppSettings, batchId: string, lawId?: string, forceLawId?: boolean): ImportResult {
    const { nuclei, contents, reports } = parseOfficialStrict(text, settings);
    const errors: string[] = [];
    reports.forEach(r => errors.push(...r.errors));

    const today = srs.todayISO();

    const gaps = contents.filter(c => c.type === 'LACUNA').map(c => ({
        id: c.id,
        litRef: c.litRef,
        type: 'LACUNA',
        payload: c.payload
    }));

    const cards: LiteralnessCard[] = nuclei.map(n => {
        const cardId = n.id;
        // Find gaps belonging to this card
        const cardGaps = gaps.filter(g => srs.canonicalizeLitRef(g.litRef) === srs.canonicalizeLitRef(cardId)).map(g => ({
             id: g.id,
             text: g.payload.lacuna_text || g.payload.text,
             correct: g.payload.correct_letter || g.payload.correct || 'A',
             options: g.payload.options || { A: 'Erro' },
             questionRef: `GAP-${g.payload.idx || '?'}`
        }));

        const card: LiteralnessCard = {
            id: cardId,
            lawId: forceLawId && lawId ? lawId : (n.lawId || lawId || 'Geral'), // Use n.lawId derived in parser
            article: n.ARTICLE || n.article || 'Artigo',
            topic: n.TOPIC || 'Geral',
            phase1Full: n.PHASE1_FULL || '',
            partsSummary: n.PARTS_SUMMARY || n.RESUMO_POR_PARTES || '',
            keywordsProva: n.KEYWORDS_PROVA || '',
            riscoFcc: n.RISCO_FCC || '',
            gancho: n.GANCHO_MNEMONICO || '',
            storytelling: n.STORYTELLING || '',
            feynmanExplanation: n.FEYNMAN || '',
            createdAt: today, nextReviewDate: today, lastReviewedAt: today, masteryScore: 0, totalAttempts: 0,
            stability: settings.srsV2.S_default_days,
            batteryProgress: 0, progressionLevel: 0, userNotes: '',
            contentType: 'LAW_DRY', importBatchId: batchId,
            extraGaps: cardGaps 
        };
        card.studyFlow = buildReadingSteps(card);
        return card;
    });

    const questions: Question[] = contents.filter(c => c.type === 'QUESTION').map(c => {
        const p = c.payload;

        return {
            id: c.id,
            questionRef: p.questionRef,
            questionText: p.questionText,
            options: p.options, // Already sanitized in parser
            correctAnswer: p.correctAnswer,

            explanation: p.EXPLANATION || '',
            explanationTech: p.EXPLANATION_TECH || '',
            explanationStory: p.EXPLANATION_STORY || '',
            feynmanQuestions: p.PERGUNTAS_FEYNMAN || '',

            guiaTrapscan: p.GUIA_TRAPSCAN || '',
            keyDistinction: p.KEY_DISTINCTION || '',
            anchorText: p.ANCHOR_TEXT || '',

            wrongDiagnosis: p.WRONG_DIAGNOSIS || '',
            // Map strings to objects if needed (Parser already did basic map for options, these might be strings)
            distractorProfile: parseDiagnosisMap(p.DISTRACTOR_PROFILE), 
            wrongDiagnosisMap: parseDiagnosisMap(p.WRONG_DIAGNOSIS_MAP),

            subject: p.DISCIPLINE || cards.find(card => card.id === c.litRef)?.lawId || 'Geral',
            topic: p.TOPIC || cards.find(card => card.id === c.litRef)?.article || 'Geral',
            lawRef: c.litRef,

            importBatchId: batchId,
            totalAttempts: 0, masteryScore: 0, attemptHistory: [],
            stability: settings.srsV2.S_default_days, nextReviewDate: today,
            createdAt: today, lastAttemptDate: '', errorCount: 0, timeSec: 0,
            selfEvalLevel: 0, willFallExam: false, srsStage: 0, correctStreak: 0,
            srsVersion: 2, sequenceNumber: 0, comments: '', 
            questionType: p.TYPE || 'Literalidade',

            hotTopic: !!p.HOT,
            isCritical: !!p.CRIT,
            isFundamental: !!p.FUND
        } as unknown as Question;
    });

    const flashcards: Flashcard[] = contents.filter(c => c.type === 'FLASHCARD' || c.type === 'PAIR').map(c => {
        const p = c.payload;
        const tags = p.TAGS ? p.TAGS.split(',').map((t:string)=>t.trim()) : [];
        if (c.type === 'PAIR' && !tags.includes('pair-match')) tags.push('pair-match');
        if (!tags.includes(c.litRef)) tags.push(c.litRef);

        return {
            id: c.id,
            front: p.FRONT || 'Frente Vazia',
            back: p.BACK || 'Verso Vazio',
            discipline: p.DISCIPLINE || cards.find(card => card.id === c.litRef)?.lawId || 'Geral',
            topic: p.TOPIC_TITLE || cards.find(card => card.id === c.litRef)?.article || 'Geral',
            tags: tags,
            type: 'basic',
            importBatchId: batchId, totalAttempts: 0, masteryScore: 0,
            stability: settings.srsV2.S_default_days, nextReviewDate: today,
            createdAt: today, updatedAt: today, lastAttemptDate: '',
            timeSec: 0, selfEvalLevel: 0, attemptHistory: [], masteryHistory: [],
            pairMatchPlayed: false, comments: ''
        } as unknown as Flashcard;
    });

    return {
        batchId, cards, questions, flashcards, gaps,
        stats: {
            cards: cards.length,
            questions: questions.length,
            flashcards: flashcards.filter(f => !f.tags.includes('pair-match')).length,
            pairs: flashcards.filter(f => f.tags.includes('pair-match')).length,
            gaps: gaps.length
        },
        errors
    };
}

export function enforceTargetLinkage(result: ImportResult, targetId: string): ImportResult {
    const canon = srs.canonicalizeLitRef(targetId);
    return {
        ...result,
        questions: (result.questions || []).map(q => ({ ...q, lawRef: canon })),
        flashcards: (result.flashcards || []).map(f => ({ ...f, tags: [...new Set([...(f.tags || []), canon])] })),
        // Also relink gaps if we were appending
        gaps: (result.gaps || []).map(g => ({ ...g, litRef: canon, id: idGen.makeDeterministicId(canon, 'LACUNA', g.payload.idx || 99) }))
    };
}

export function cleanBatchForExport(batch: any): any { return batch; }

export async function runImportSelfTest(): Promise<any> {
    const testText = `LIT_REF: TEST_01\nLAW_ID: TEST\nARTICLE: Art 1\nPHASE1_FULL: Texto\n\nQ_REF: Q1\nQ_TEXT: T?\nOPT_A: Sim\nOPT_B: Não\nCORRECT: A`;
    const mockSettings: any = { srsV2: { S_default_days: 1 } };
    const result = parseLitRefText(testText, mockSettings, 'TEST_BATCH');
    return { parseResult: result, auditReport: [] };
}
